var QUESTIONS = [{"task":"Task 1: Manage Conflict","q":"أثناء اجتماع تخطيط السبرنت، يتجادل اثنان من كبار المطورين بشدة حول التصميم المعماري للنظام، ويبدأ النقاش في تعطيل الاجتماع. ما أول إجراء يجب على مدير المشروع اتخاذه؟","opts":["تأجيل الاجتماع وطلب من الفريق التصويت على التصميم لاحقاً","التدخل لفهم مصدر الخلاف وتحليل سياقه قبل اقتراح حل","اتخاذ قرار سريع باختيار أحد التصميمين للحفاظ على وتيرة العمل","تصعيد المسألة فوراً إلى الراعي للحصول على توجيه"],"ans":"B","exp":"وفقاً للممارسات الموصى بها في PMP، تتمثل الخطوة الأولى في إدارة النزاع في تفسير مصدر النزاع وتحليل سياقه قبل تقييم الحلول. القرارات السريعة أو التصعيد المبكر تتجاوز خطوة التشخيص الأساسية.","id":1},{"task":"Task 1: Manage Conflict","q":"اكتشف مدير المشروع أن مصدر النزاع بين عضوين في الفريق ليس فنياً بل يتعلق بصراع شخصي قديم. ما أنسب نهج لحل النزاع؟","opts":["تجاهل النزاع ما دام لا يؤثر على المخرجات الفنية","فصل العضوين على مهام مختلفة بشكل دائم","الاجتماع مع كل طرف على حدة لفهم السياق ثم التوفيق بينهما","إبلاغ الموارد البشرية مباشرة لاتخاذ إجراء"],"ans":"C","exp":"تحليل سياق النزاع ثم اختيار حل مناسب يعد جوهر إدارة النزاع. اللقاء الفردي يساعد على فهم وجهات النظر قبل المصالحة، وهو أنسب من التجاهل أو الفصل أو التصعيد المبكر.","id":2},{"task":"Task 1: Manage Conflict","q":"في فريق هجين، يشتكي أحد المطورين الافتراضيين من أن زملاءه في الموقع يستثنونه من القرارات الفنية المهمة. كيف ينبغي لمدير المشروع تفسير هذا النزاع؟","opts":["صراع شخصي بين أفراد ولا يستوجب تدخلاً","نزاع ناتج عن اختلاف في القيم الأساسية","نزاع إجرائي مرتبط بطريقة اتخاذ القرار والتواصل في فريق موزع","مشكلة أداء فردي للمطور الافتراضي"],"ans":"C","exp":"هذا نزاع إجرائي/هيكلي يتعلق بآليات التواصل واتخاذ القرار في الفرق الموزعة، وليس نزاعاً شخصياً. تفسير المصدر الصحيح يقود إلى حل صحيح، مثل إعادة تصميم بروتوكولات اتخاذ القرار.","id":3},{"task":"Task 1: Manage Conflict","q":"وفقاً لنموذج توماس-كيلمان لحل النزاعات، أي من المواقف التالية يستدعي استخدام أسلوب التعاون (Collaborating/Problem-Solving)؟","opts":["عندما يكون الوقت ضيقاً جداً وهناك حاجة لقرار فوري","عندما تكون المسألة بسيطة وغير مهمة لأي طرف","عندما تكون الحاجة لحل مرضٍ لجميع الأطراف ولدى الفريق وقت كافٍ","عندما يكون أحد الأطراف على حق تماماً والآخر مخطئ تماماً"],"ans":"C","exp":"التعاون هو أسلوب win-win يتطلب وقتاً وثقة، ويستخدم عندما تكون المصالح المتبادلة مهمة لجميع الأطراف. هو الأسلوب المفضل في PMI لأنه يقود إلى حلول مستدامة.","id":4},{"task":"Task 1: Manage Conflict","q":"خلال جلسة المراجعة (Retrospective)، عبّر أحد أعضاء الفريق عن إحباطه من قرار اتخذه مدير المشروع الأسبوع الماضي. ما أفضل استجابة من مدير المشروع؟","opts":["الدفاع عن قراره وشرح أنه كان الأفضل في تلك اللحظة","الاستماع بفهم، تقدير وجهة النظر، ومناقشة كيفية تحسين القرارات المستقبلية","إنهاء الموضوع لأن جلسات المراجعة ليست لمناقشة قرارات الإدارة","الاعتراف بالخطأ والوعد بعدم تكراره دون نقاش"],"ans":"B","exp":"جلسات المراجعة فرصة لتعلم منظم. الاستماع الفعال والتعاون لإيجاد حلول مستقبلية يحافظ على ثقة الفريق ويظهر القيادة الخادمة، وهو ما توصي به PMI.","id":5},{"task":"Task 1: Manage Conflict","q":"يدخل عضوان في الفريق في نزاع متكرر حول أولويات العمل. تكتشف أن السبب الجذري هو غموض في تعريف معايير قبول المهام. ما الإجراء الأنسب؟","opts":["حل النزاع المباشر بين العضوين فقط ثم متابعة العمل","معالجة السبب الجذري بوضع معايير قبول واضحة وإعادة مراجعتها مع الفريق","تعيين عضو ثالث للتحكيم بينهما في كل مرة","إعادة توزيع المهام بشكل لا يضع الاثنين في نفس المسار"],"ans":"B","exp":"معالجة السبب الجذري أكثر فاعلية من الحلول السطحية المتكررة. الغموض في معايير القبول هو سبب نظامي، وعلاجه يمنع تكرار النزاع.","id":6},{"task":"Task 1: Manage Conflict","q":"أي مرحلة من مراحل تطور تاكمان (Tuckman) يُتوقع فيها أن يكون النزاع داخل الفريق في ذروته؟","opts":["Forming (التشكيل)","Storming (العصف)","Norming (التطبيع)","Performing (الأداء)"],"ans":"B","exp":"مرحلة Storming هي مرحلة الصراعات حيث يبدأ الأعضاء في فرض آرائهم، وهي طبيعية ومتوقعة. على مدير المشروع التعرف عليها وقيادة الفريق نحو Norming.","id":7},{"task":"Task 1: Manage Conflict","q":"يطلب أحد أصحاب المصلحة الرئيسيين إضافة ميزة لم تكن في النطاق، بينما يرفض راعي المشروع بسبب الميزانية. كيف يجب على مدير المشروع التعامل مع هذا النزاع؟","opts":["تنفيذ طلب صاحب المصلحة لأنه مهم","رفض الطلب بشكل قاطع للحفاظ على النطاق","تحليل سياق النزاع، توضيح التأثيرات لكلا الطرفين، وتيسير حوار يصل إلى حل متفق عليه","تقديم الطلب لمجلس مراقبة التغيير فوراً دون مناقشة"],"ans":"C","exp":"دور مدير المشروع كميسر للنزاعات بين أصحاب المصلحة هو تحليل السياق، توضيح المقايضات بشفافية، وتيسير حوار بناء. CCB قد يكون خطوة لاحقة بعد توضيح الموقف.","id":8},{"task":"Task 1: Manage Conflict","q":"في فريق Agile، يصرّ Product Owner على إعادة ترتيب أولويات Backlog في منتصف السبرنت، مما يثير غضب الفريق. ما أفضل تصرف لـ Scrum Master؟","opts":["إجبار الفريق على قبول التغيير لأن Product Owner مسؤول عن الـ Backlog","تسهيل حوار بين Product Owner والفريق لشرح مبادئ Scrum بشأن الالتزامات داخل السبرنت","إلغاء السبرنت فوراً والبدء بسبرنت جديد","تجاهل طلب Product Owner لحماية الفريق"],"ans":"B","exp":"Scrum Master قائد خادم يثقّف الأطراف على مبادئ Agile. التغييرات داخل السبرنت تتطلب تفاهماً، وفي حالات نادرة قد تتطلب إلغاء السبرنت، لكن الحوار هو الخطوة الأولى.","id":9},{"task":"Task 1: Manage Conflict","q":"أي من أساليب حل النزاع التالية يُعتبر الأقل فعالية على المدى الطويل وفقاً لمعايير PMI؟","opts":["Collaborating (التعاون)","Compromising (التسوية)","Smoothing/Accommodating (التهدئة)","Withdrawing/Avoiding (الانسحاب)"],"ans":"D","exp":"Withdrawing يُعدّ الأقل فعالية لأنه يؤجل النزاع دون حله. Collaborating هو الأفضل، يليه Compromising. Smoothing يخفي النزاع جزئياً لكنه أفضل من تجاهله تماماً.","id":10},{"task":"Task 1: Manage Conflict","q":"أثناء مرحلة التنفيذ، يقدّم اثنان من أعضاء الفريق حلين تقنيين متعارضين كلاهما صحيح فنياً. ماذا يجب أن يفعل مدير المشروع؟","opts":["اختيار الحل الأقل تكلفة دون نقاش","تيسير جلسة فنية لتقييم الحلين وفق معايير المشروع والوصول إلى توصية مشتركة","السماح لكل عضو بتنفيذ حله ومقارنة النتائج","تأجيل القرار حتى يقرر العميل"],"ans":"B","exp":"النزاع البنّاء حول الحلول التقنية يُعالج بتيسير الحوار وفق معايير موضوعية (تكلفة، جودة، قابلية التوسع). تنفيذ حلين هدر للموارد.","id":11},{"task":"Task 1: Manage Conflict","q":"يتصاعد نزاع بين فريقين في مشروع كبير، ويبدأ ينعكس على المخرجات. ما الإجراء الأكثر استراتيجية؟","opts":["فصل الفريقين تماماً وإعادة هيكلة العمل","تشخيص السبب الجذري على مستوى الفريقين، وعقد ورشة بناء فريق وتوحيد المعايير","تصعيد المسألة فوراً لراعي المشروع","استبدال قادة الفريقين"],"ans":"B","exp":"النزاعات بين الفرق غالباً ما تنجم عن غموض في الأدوار أو معايير مختلفة. ورشة بناء فريق وتوحيد المعايير تعالج السبب الجذري وتبني الثقة.","id":12},{"task":"Task 1: Manage Conflict","q":"أعضاء فريقك يأتون من ثقافات مختلفة، وأحدهم يعتبر النقد المباشر إهانة بينما الآخر يعتبره احتراماً. كيف تتعامل مع هذا النوع من النزاع؟","opts":["فرض أسلوب تواصل موحد على الجميع","تجاهل الاختلافات الثقافية والتركيز على المهام فقط","تحليل السياق الثقافي، وضع قواعد تواصل تحترم الاختلافات، وتدريب الفريق على الذكاء الثقافي","تجنب وضع أعضاء من ثقافات مختلفة في نفس المهام"],"ans":"C","exp":"الذكاء الثقافي جزء من إدارة الفرق الدولية. وضع قواعد تواصل واضحة تحترم الاختلافات يعالج السبب الجذري ويبني فريقاً مترابطاً.","id":13},{"task":"Task 1: Manage Conflict","q":"يدخل عضو في الفريق في نزاع متكرر مع زملائه. عند التحقيق تكتشف أنه يعاني من ضغط شخصي خارج العمل. ما أنسب تصرف؟","opts":["تجاهل الأسباب الشخصية والتركيز فقط على سلوك العمل","مقابلته بشكل خاص بتعاطف، تقديم الدعم المتاح (مرونة في الجدول، توجيه لبرامج المساعدة)، ومتابعة الأداء","إخراجه من الفريق فوراً","إخبار باقي الفريق بسبب سلوكه ليتفهموا"],"ans":"B","exp":"القيادة الخادمة والذكاء العاطفي يتطلبان فهم الأبعاد الإنسانية. الدعم الخاص والمحترم يحافظ على كرامة الشخص ويعالج المشكلة. مشاركة المعلومات الشخصية مع الفريق انتهاك للخصوصية.","id":14},{"task":"Task 1: Manage Conflict","q":"في اجتماع، يصرّ أحد كبار أصحاب المصلحة على فرض رأيه برفع صوته ومقاطعة الآخرين. ما أفضل استجابة لمدير المشروع؟","opts":["السماح له بالاستمرار حفاظاً على العلاقة","مواجهته بحدة في الاجتماع لإيقافه","إعادة توجيه المحادثة بهدوء، التأكيد على قواعد الاجتماع، ومتابعته بعد الاجتماع لمعالجة المخاوف الكامنة","إنهاء الاجتماع فوراً"],"ans":"C","exp":"إعادة التوجيه الهادئة تحافظ على فعالية الاجتماع دون مواجهة محرجة. المتابعة الفردية لاحقاً تعالج الأسباب الجذرية وتحافظ على العلاقة.","id":15},{"task":"Task 1: Manage Conflict","q":"أي من العبارات التالية تصف بدقة أكبر مفهوم النزاع في بيئة المشاريع وفقاً لـ PMI؟","opts":["النزاع دائماً سلبي ويجب تجنبه بأي ثمن","النزاع طبيعي وحتمي، ويمكن أن يكون بنّاءً عند إدارته بفعالية","النزاع علامة على ضعف القيادة","النزاع يحدث فقط بسبب اختلافات شخصية"],"ans":"B","exp":"تنظر PMI إلى النزاع باعتباره ظاهرة طبيعية وقد يكون مفيداً (نزاع بنّاء حول الأفكار) إذا أدير بشكل صحيح. تجنبه تماماً ليس واقعياً ولا مفيداً.","id":16},{"task":"Task 1: Manage Conflict","q":"بعد حل نزاع بين عضوين في الفريق، لاحظت أن السلوك السلبي عاد بعد أسبوعين. ما الإجراء الصحيح؟","opts":["اعتبار النزاع منتهياً وتجاهل العودة","إعادة تقييم الحل، التحقق من السبب الجذري الحقيقي، ومتابعة دورية للتأكد من استدامة الحل","تطبيق إجراء تأديبي على الطرفين فوراً","إخراج أحدهما من الفريق"],"ans":"B","exp":"إعادة التقييم المستمر جزء من إدارة النزاع. عودة النزاع تشير إلى أن السبب الجذري لم يُعالج بشكل كافٍ، وتتطلب تشخيصاً أعمق.","id":17},{"task":"Task 1: Manage Conflict","q":"أنت مدير مشروع لفريق Agile، ويتجادل المطورون مع QA حول معايير الاختبار. ما أفضل نهج لحل النزاع؟","opts":["اتخاذ قرار من جانبك لحسم النقاش","تيسير جلسة لمواءمة تعريف \"Done\" وإشراك الفريق في بناء معايير الجودة المشتركة","فصل دور QA عن فريق التطوير","السماح للمطورين بتجاوز QA لتسريع التسليم"],"ans":"B","exp":"بناء تعريف \"Done\" المشترك في Agile هو ممارسة جوهرية تحل نزاعات الجودة بطريقة تعاونية وتمنح الفريق ملكية المعايير.","id":18},{"task":"Task 2: Lead a Team","q":"بدأت للتو قيادة فريق جديد لمشروع استراتيجي. ما الإجراء الأكثر أولوية في الأيام الأولى؟","opts":["إعداد جدول زمني تفصيلي للمشروع","إنشاء رؤية ورسالة واضحة للمشروع ومشاركتها مع الفريق","تعيين المهام للأعضاء بناءً على سيرهم الذاتية","البدء بأول اجتماع حالة أسبوعي"],"ans":"B","exp":"وضع رؤية ورسالة واضحة هو حجر الأساس للقيادة الفعالة. تمنح الفريق هدفاً مشتركاً وتوجّه القرارات اليومية. الجدول والمهام تأتي لاحقاً.","id":19},{"task":"Task 2: Lead a Team","q":"أي من الأنماط القيادية التالية يتوافق أكثر مع مبادئ القيادة الخادمة (Servant Leadership)؟","opts":["إصدار أوامر واضحة ومتابعة التنفيذ الصارم","إزالة العوائق أمام الفريق وتمكينه من اتخاذ القرارات","اتخاذ جميع القرارات الرئيسية مركزياً","التركيز على الإبلاغ التفصيلي للإدارة العليا"],"ans":"B","exp":"القيادة الخادمة تضع احتياجات الفريق في المقدمة، تركز على إزالة العوائق، تطوير الأفراد، وتمكين الفريق. هي النمط الموصى به في بيئات Agile و PMI.","id":20},{"task":"Task 2: Lead a Team","q":"فريقك يضم أعضاء من خلفيات متنوعة (تقنية، عملية، عمرية، ثقافية). كيف تستثمر هذا التنوع لصالح المشروع؟","opts":["توحيد أسلوب العمل لتقليل الاختلافات","تخصيص المهام بناءً على الأقدمية فقط","تشجيع تبادل وجهات النظر، تخصيص المهام وفق نقاط القوة، وبناء بيئة شاملة آمنة","فصل الأعضاء على فرق متجانسة"],"ans":"C","exp":"التنوع مصدر قوة عندما يُدار بذكاء. تشجيع الأصوات المتنوعة وبناء الأمان النفسي يطلق إمكانات الفريق ويحسّن جودة القرارات.","id":21},{"task":"Task 2: Lead a Team","q":"أي من الأساليب التالية أكثر فاعلية لإلهام وتحفيز الفريق في مشروع طويل الأمد؟","opts":["زيادة الرواتب فقط","ربط العمل اليومي بالرؤية الأكبر، الاحتفاء بالإنجازات، وتوفير فرص النمو","زيادة ساعات العمل لإنجاز المهام أسرع","تطبيق رقابة دقيقة على أداء كل فرد"],"ans":"B","exp":"نظرية هرتزبرغ تظهر أن الراتب عامل صحة وليس محفزاً حقيقياً. المعنى، الاعتراف، والنمو هي محركات الدافعية الداخلية المستدامة.","id":22},{"task":"Task 2: Lead a Team","q":"في موقف يتطلب قراراً سريعاً أثناء أزمة فنية، أي نمط قيادي يكون الأنسب؟","opts":["النمط التشاركي (Participative)","النمط التوجيهي (Directive)","النمط التفويضي (Delegating)","النمط الداعم (Supporting)"],"ans":"B","exp":"وفقاً لنموذج القيادة الظرفية، الأزمات والمواقف الحرجة تستدعي قيادة توجيهية واضحة. النمط القيادي يجب أن يتكيف مع الموقف ومستوى نضج الفريق.","id":23},{"task":"Task 2: Lead a Team","q":"ما الغرض الأساسي من \"عقد الفريق\" (Team Charter) في مشاريع PMP؟","opts":["وثيقة قانونية ملزمة بين أعضاء الفريق","بديل عن خطة المشروع الرسمية","وثيقة تحدد قيم الفريق وقواعد العمل وآليات اتخاذ القرار والتواصل","قائمة بأسماء وعناوين الأعضاء"],"ans":"C","exp":"عقد الفريق هو وثيقة تعاونية تحدد كيفية عمل الفريق معاً: القيم، التواصل، اتخاذ القرار، حل النزاع، وقواعد السلوك. إنشاؤه مع الفريق يبني الالتزام.","id":24},{"task":"Task 2: Lead a Team","q":"لاحظت أن أحد أعضاء الفريق ذوي الأداء العالي بدأ يفقد الحماس. ما أنسب تصرف؟","opts":["تجاهل ذلك ما دام أداؤه لا يزال مقبولاً","زيادة رقابتك عليه","إجراء محادثة فردية لفهم السبب، واستكشاف فرص نمو أو تحديات جديدة تتناسب معه","نقله إلى مشروع آخر"],"ans":"C","exp":"الأداء العالي مع تراجع الحماس قد يشير إلى الملل أو الحاجة لتحدي جديد. القائد الخادم يستثمر في فهم ودعم احتياجات أفراد فريقه.","id":25},{"task":"Task 2: Lead a Team","q":"كيف يمكن لمدير المشروع تحليل تأثير أصحاب المصلحة على المشروع بفعالية؟","opts":["الاعتماد على الحدس الشخصي فقط","استخدام أدوات مثل مصفوفة القوة/الاهتمام، مصفوفة التأثير/التأثر، أو نموذج البروز","سؤال الراعي عن من هم الأهم","افتراض أن جميع أصحاب المصلحة لديهم نفس مستوى التأثير"],"ans":"B","exp":"أدوات تحليل أصحاب المصلحة الموضوعية (Power/Interest Grid, Salience Model) توفر إطاراً منهجياً لتوجيه استراتيجيات الإشراك.","id":26},{"task":"Task 2: Lead a Team","q":"في فريق ناضج وذو خبرة عالية، أي نمط قيادي يكون الأكثر فعالية؟","opts":["التوجيهي (إصدار أوامر محددة)","التفويضي (منح استقلالية كبيرة مع متابعة الأهداف)","البيروقراطي (التركيز على القواعد)","الأوتوقراطي (اتخاذ كل القرارات وحدك)"],"ans":"B","exp":"وفقاً لنموذج هيرسي وبلانشارد للقيادة الظرفية، الفرق الناضجة عالية الكفاءة تستجيب أفضل للأسلوب التفويضي الذي يحترم خبراتها.","id":27},{"task":"Task 2: Lead a Team","q":"وفقاً لمفهوم القيادة الخادمة، أي من المسؤوليات التالية ليست من مهام القائد الخادم؟","opts":["إزالة العوائق أمام الفريق","تطوير قدرات الأفراد","التحكم في كل قرار صغير لضمان الجودة","بناء بيئة آمنة نفسياً"],"ans":"C","exp":"القائد الخادم يثق بفريقه ويفوض القرارات الملائمة. التحكم الدقيق يقتل الإبداع والملكية، وهو نقيض القيادة الخادمة.","id":28},{"task":"Task 2: Lead a Team","q":"تم تعيينك مديراً لمشروع تحول رقمي يضم 5 فرق فرعية. كيف توحّد الرؤية بين الجميع؟","opts":["إرسال بريد إلكتروني واحد يحتوي على الرؤية","صياغة الرؤية مع قادة الفرق، عقد جلسة إطلاق شاملة، وتعزيز الرؤية في الاجتماعات الدورية","تركها لكل قائد فريق فرعي ليصيغها بطريقته","نشرها على لوحة المشروع فقط"],"ans":"B","exp":"بناء الرؤية بشكل تشاركي ثم نشرها وتعزيزها بشكل متعدد القنوات يضمن فهماً والتزاماً مشتركين. التعزيز المستمر ضروري لاستدامة التركيز.","id":29},{"task":"Task 2: Lead a Team","q":"ما الفرق الأساسي بين الإدارة والقيادة في سياق المشاريع؟","opts":["لا يوجد فرق، المصطلحان مترادفان","الإدارة تركز على الأنظمة والعمليات، بينما القيادة تركز على الأشخاص والرؤية والتحفيز","القيادة لا تحتاج إلى مهارات تقنية","الإدارة أهم من القيادة في المشاريع"],"ans":"B","exp":"كلاهما ضروري للمشاريع. الإدارة تنظم العمل (تخطيط، جدولة، رقابة)، والقيادة توجّه الأشخاص (رؤية، إلهام، تمكين). PMP يتطلب الاثنين.","id":30},{"task":"Task 2: Lead a Team","q":"أي من العبارات التالية لا تنتمي لمبادئ القيادة الخادمة في PMBOK 7؟","opts":["وضع احتياجات الفريق قبل احتياجات القائد","التركيز على نمو الأفراد","إزالة العوائق التنظيمية","اتخاذ جميع القرارات منفرداً لضمان السرعة"],"ans":"D","exp":"القيادة الخادمة تشرك الفريق في القرارات وتفوّضها عند الإمكان. اتخاذ القرارات منفرداً يناقض جوهر هذا النمط القيادي.","id":31},{"task":"Task 2: Lead a Team","q":"بعد بدء المشروع بأسبوعين، تلاحظ أن أحد كبار أصحاب المصلحة يحاول التأثير على الفريق مباشرة بتجاوزك. ما أفضل تصرف؟","opts":["تجاهل الموقف لتجنب المواجهة","منع جميع أعضاء الفريق من التحدث مع أصحاب المصلحة","مقابلة صاحب المصلحة بشكل خاص، فهم اهتماماته، وإعادة بناء قنوات التواصل الصحيحة","تصعيد المسألة فوراً للراعي"],"ans":"C","exp":"محاولات التأثير المباشر غالباً تنبع من عدم رضا أو احتياج غير ملبى. الحوار الخاص يفهم السبب ويعيد ضبط القنوات بطريقة محترمة دون إضعاف العلاقة.","id":32},{"task":"Task 2: Lead a Team","q":"في مشروع Agile، يطلب صاحب المنتج اجتماعاً يومياً مع المطورين مع وجود Daily Scrum. كيف تتصرف كـ Scrum Master؟","opts":["السماح بالاجتماع الإضافي لإرضاء صاحب المنتج","رفض الطلب بشكل قاطع","تثقيف صاحب المنتج بدوره في Scrum، توضيح أن Daily Scrum للمطورين، واقتراح آليات مناسبة للتواصل","إخراج Daily Scrum من جدول الفريق"],"ans":"C","exp":"Scrum Master يحمي الفريق ويثقّف الأطراف على الإطار. صاحب المنتج له قنوات تواصل متعددة (Refinement, Review) لكن لا يدير Daily Scrum.","id":33},{"task":"Task 2: Lead a Team","q":"كيف يمكن لمدير المشروع تطبيق مبدأ \"دعم التجارب المتنوعة\" في الفريق عملياً؟","opts":["تجاهل وجهات النظر المختلفة لتسريع القرارات","تخصيص وقت لاجتماعات لاستماع الأصوات المختلفة، وتدوير قيادة الاجتماعات، وإنشاء قنوات للأفكار","اختيار وجهة النظر التي تتوافق معه شخصياً","السماح فقط لأكبر الأعضاء سناً بالكلام"],"ans":"B","exp":"دعم التجارب المتنوعة يتطلب إجراءات عملية: مساحة للأصوات، تدوير المسؤوليات، وقنوات متعددة لجمع الأفكار.","id":34},{"task":"Task 2: Lead a Team","q":"في تخطيط نظام مكافآت للفريق، ما أفضل توصية وفقاً لمبادئ PMP؟","opts":["مكافآت فردية فقط لأفضل أداء","مكافآت جماعية فقط لتشجيع التعاون","مزيج من المكافآت الجماعية لتعزيز التعاون والاعتراف الفردي للإنجازات المتميزة، بشكل عادل وشفاف","عدم تقديم أي مكافآت لتجنب التحيز"],"ans":"C","exp":"نظام المكافآت الفعال يوازن بين التعاون والإنجاز الفردي، ويكون شفافاً وعادلاً. الاعتماد على نوع واحد فقط يخلق سلوكيات غير صحية.","id":35},{"task":"Task 2: Lead a Team","q":"كيف تحدد النمط القيادي المناسب لكل عضو في فريقك؟","opts":["تطبيق نفس النمط على الجميع للعدالة","تقييم مستوى الكفاءة والالتزام لكل عضو، وتكييف النمط (توجيهي/تدريبي/داعم/تفويضي)","اختيار النمط الذي تفضله شخصياً","السؤال عن النمط المفضل لرئيسك"],"ans":"B","exp":"نموذج القيادة الظرفية (Situational Leadership) يقترح تكييف النمط مع كل فرد بناءً على كفاءته والتزامه بالمهمة. هذا أكثر فاعلية من نمط موحد.","id":36},{"task":"Task 2: Lead a Team","q":"أحد كبار أصحاب المصلحة لديه تأثير كبير لكن اهتمامه بالمشروع منخفض. ما الاستراتيجية الأنسب؟","opts":["تجاهله لأن اهتمامه منخفض","إغراقه بالتفاصيل اليومية","إبقاؤه راضياً عبر تحديثات استراتيجية موجزة، ومراقبة أي تغير في اهتمامه","إعطاؤه قرارات يومية ليشعر بالمسؤولية"],"ans":"C","exp":"وفقاً لمصفوفة Power/Interest، أصحاب المصلحة عاليي القوة منخفضي الاهتمام يستوجبون استراتيجية \"Keep Satisfied\" بتحديثات استراتيجية ومراقبة مستمرة.","id":37},{"task":"Task 2: Lead a Team","q":"ما الفرق الأساسي بين القائد التحويلي (Transformational) والقائد المعاملاتي (Transactional)؟","opts":["لا فرق بينهما","التحويلي يلهم التغيير والنمو الشخصي، بينما المعاملاتي يركز على الحوافز والعقوبات المرتبطة بالأداء","المعاملاتي أكثر فعالية دائماً","التحويلي يستخدم فقط في الشركات الكبيرة"],"ans":"B","exp":"القيادة التحويلية تركز على الإلهام والمعنى وتطوير الأتباع. المعاملاتية تعتمد على نظام واضح من المكافآت/العقوبات. كلاهما له موضعه.","id":38},{"task":"Task 3: Support Team Performance","q":"ما أفضل ممارسة لتقييم أداء فريق المشروع؟","opts":["تقييم الأداء سنوياً مع باقي تقييمات الموارد البشرية","تقييم مستمر مقابل مؤشرات أداء رئيسية محددة مسبقاً مع تغذية راجعة منتظمة","الاعتماد على الانطباع العام لمدير المشروع","التقييم فقط عند ظهور مشاكل"],"ans":"B","exp":"التقييم المستمر مقابل KPIs محددة يوفر بيانات موضوعية، يمنح فرصاً لتحسين فوري، ويتوافق مع ممارسات PMI الحديثة في إدارة الأداء.","id":39},{"task":"Task 3: Support Team Performance","q":"أي من مؤشرات الأداء التالية الأكثر فائدة في فريق Agile؟","opts":["عدد ساعات العمل لكل عضو","Velocity, Cycle Time, Sprint Goal Achievement, جودة المخرجات","عدد الاجتماعات الحضورية أسبوعياً","حجم الوثائق المنتجة"],"ans":"B","exp":"مؤشرات Agile تركز على القيمة المسلّمة والكفاءة (Velocity, Cycle Time) وتحقيق الأهداف، وليس على المدخلات أو الإجراءات الشكلية.","id":40},{"task":"Task 3: Support Team Performance","q":"أحد أعضاء الفريق يقدّم أداءً ممتازاً لكنه يعمل بمعزل عن الآخرين. كيف تتعامل مع الموقف؟","opts":["تركه بمفرده ما دام أداؤه ممتازاً","محادثته لفهم سبب العزلة، وتقدير أدائه مع تشجيع التعاون لنقل المعرفة وتقوية الفريق","إخراجه من الفريق بسبب عدم التعاون","خفض تقييمه بسبب العزلة"],"ans":"B","exp":"الأداء الفردي مهم، لكن التعاون ونقل المعرفة جزء من أداء الفريق. الحوار البنّاء يحافظ على الأداء ويضيف بعد التعاون دون عقاب.","id":41},{"task":"Task 3: Support Team Performance","q":"ما النهج الأنسب لتقديم تغذية راجعة سلبية لعضو في الفريق؟","opts":["علنياً في اجتماع الفريق ليتعلم الآخرون","كتابياً عبر البريد لتوثيق الموقف","بشكل خاص، فورياً، محدداً بسلوك معين، ومرتبطاً بالأثر، مع اقتراح بدائل","تجنبها للحفاظ على العلاقة"],"ans":"C","exp":"نموذج SBI (Situation-Behavior-Impact) أو DESC للتغذية الراجعة الفعالة: خاص، محدد، فوري، ويتضمن خطوات تحسين. التغذية الراجعة العلنية تضر بالكرامة.","id":42},{"task":"Task 3: Support Team Performance","q":"كيف تتحقق من أن خطة تحسين الأداء التي وضعتها لأحد أعضاء الفريق فعّالة؟","opts":["الانتظار حتى نهاية المشروع لتقييم النتائج","متابعة دورية وقياس مقابل المؤشرات المتفق عليها، وتعديل الخطة عند الحاجة","السؤال عن انطباعات باقي الفريق","افتراض أن الخطة ناجحة ما لم تأتِ شكاوى"],"ans":"B","exp":"التحقق من تحسن الأداء يتطلب مؤشرات قابلة للقياس ومراجعات منتظمة، مع مرونة لتعديل الخطة بناءً على البيانات الفعلية.","id":43},{"task":"Task 3: Support Team Performance","q":"ما الفرق بين الإرشاد (Coaching) والتوجيه (Mentoring)؟","opts":["لا فرق بينهما","الإرشاد يركز على مهارات وأهداف محددة في فترة قصيرة، بينما التوجيه أوسع وأطول وأكثر تركيزاً على تطوير المسار المهني","الإرشاد للمبتدئين والتوجيه للخبراء","التوجيه يكون داخلياً والإرشاد خارجياً"],"ans":"B","exp":"Coaching تكتيكي يستهدف مهارات محددة، أما Mentoring استراتيجي طويل الأمد يتعلق بالنمو المهني الشامل. كلاهما له دور في تطوير الفريق.","id":44},{"task":"Task 3: Support Team Performance","q":"لاحظت أن أحد أعضاء الفريق يحتاج إلى تطوير مهارات تقنية محددة. ما أفضل نهج لدعمه؟","opts":["إخباره بأن يتعلم بنفسه خارج العمل","تحديد فجوة المهارة بدقة، وضع خطة تنمية (تدريب، إرشاد، مشاريع تطبيقية)، وتخصيص موارد لذلك","نقله إلى مهام لا تتطلب تلك المهارة","تقييمه بشكل سلبي لإجباره على التعلم"],"ans":"B","exp":"دعم نمو الأفراد جزء من مسؤولية القائد. خطة تنمية مهيكلة مع موارد فعالة أنسب من اللوم أو التهرب.","id":45},{"task":"Task 3: Support Team Performance","q":"أي ممارسة تساعد أكثر في الاعتراف بنمو أعضاء الفريق؟","opts":["تجاهل التقدم لتجنب الغرور","الاعتراف العلني بالإنجازات، إتاحة فرص جديدة، وربط النمو بمسار مهني واضح","زيادة الراتب فقط","إعطاء المزيد من العمل دون اعتراف"],"ans":"B","exp":"الاعتراف العلني والفرص الجديدة من أقوى محركات الدافعية. ربط النمو بمسار مهني يعزز الالتزام طويل الأمد.","id":46},{"task":"Task 3: Support Team Performance","q":"في فريق Agile، كيف يتم تقييم أداء الفريق عادة بدلاً من الأداء الفردي؟","opts":["بناءً على عدد الساعات","بناءً على القيمة المسلمة، تحقيق أهداف السبرنت، وجودة المنتج","بناءً على الرواتب","بناءً على عدد التعليمات البرمجية المكتوبة"],"ans":"B","exp":"Agile يقيم الفريق ككل بناءً على القيمة المنجزة. التقييم الفردي قد يضر بالتعاون الجماعي.","id":47},{"task":"Task 3: Support Team Performance","q":"أحد أعضاء الفريق ذي الأداء الجيد بدأ يتراجع في الأسابيع الأخيرة. ما أول خطوة؟","opts":["تحذيره فوراً بشكل رسمي","اجتماع فردي خاص لفهم الأسباب (شخصية، فنية، تنظيمية) وتقديم الدعم المناسب","تجاهل التراجع لعله مؤقت","تكليفه بمهام أقل"],"ans":"B","exp":"تراجع الأداء له أسباب متعددة. الحوار الخاص لفهم السبب أولاً ثم وضع خطة دعم هو نهج القائد الخادم. التحذير الرسمي قبل فهم السبب قد يكون مدمراً.","id":48},{"task":"Task 3: Support Team Performance","q":"أي من العبارات التالية صحيحة بشأن مؤشرات الأداء الرئيسية (KPIs) للمشاريع؟","opts":["يجب أن تكون كثيرة لتغطية كل التفاصيل","يجب أن تكون SMART: محددة، قابلة للقياس، قابلة للتحقيق، ذات صلة، ومحددة بوقت","يجب أن تحدد من الإدارة العليا فقط","ليست ضرورية في المشاريع الصغيرة"],"ans":"B","exp":"KPIs الفعالة تتبع معايير SMART. القائمة الطويلة تشتت التركيز، والصياغة الجيدة تضمن قياساً موضوعياً وقابلاً للإدارة.","id":49},{"task":"Task 3: Support Team Performance","q":"بعد تطبيق خطة تحسين أداء لأحد أعضاء الفريق، تحققت النتائج. ما الإجراء المناسب؟","opts":["إنهاء الخطة دون أي تأكيد رسمي","توثيق التحسن، الاعتراف به علناً (بشكل لائق)، وتعزيز السلوكيات الجديدة عبر متابعة دورية","إعادة بدء الخطة من الصفر","ترقيته فوراً"],"ans":"B","exp":"تعزيز السلوكيات الإيجابية بالتوثيق والاعتراف يحافظ على المكاسب. المتابعة الدورية تمنع التراجع.","id":50},{"task":"Task 3: Support Team Performance","q":"كيف يجب أن تتعامل مع تقييم أداء عضو في فريق هجين/Agile؟","opts":["مقارنته بالأعضاء الآخرين علناً","تقييم مساهمته في القيمة المسلمة، تعاونه، نموه، واحترامه لمبادئ Agile","حساب عدد ساعاته بدقة","الاعتماد على رأي زبون واحد"],"ans":"B","exp":"تقييم الأعضاء في Agile يأخذ في الاعتبار المساهمة في القيمة، التعاون، والنمو، وليس مقاييس تقليدية كالساعات. المقارنة العلنية مدمرة للفريق.","id":51},{"task":"Task 3: Support Team Performance","q":"أي من الأساليب يساعد أكثر في تطوير مهارات الفريق بشكل مستمر؟","opts":["دورة تدريبية واحدة في بداية المشروع","خطط تنمية فردية، تبادل المعرفة الداخلي، Communities of Practice، والتعلم من الإخفاقات","الاعتماد على المعرفة الحالية فقط","التدريب فقط عند الترقية"],"ans":"B","exp":"التطوير المستمر يحتاج نهجاً متعدد الأوجه: تدريب رسمي، تعلم تعاوني، تبادل خبرات. هذا أكثر فاعلية من تدريب منفرد.","id":52},{"task":"Task 3: Support Team Performance","q":"ما أفضل توقيت لتقديم تغذية راجعة إيجابية لعضو في الفريق؟","opts":["في تقييم الأداء السنوي فقط","فوراً عند ملاحظة السلوك أو الإنجاز المتميز، وبشكل محدد وصادق","مرة في الشهر فقط","عندما يطلبها الموظف"],"ans":"B","exp":"التغذية الراجعة الإيجابية الفورية والمحددة أقوى أثراً من المعممة المؤجلة. تعزز السلوكيات المرغوبة وتبني الثقة.","id":53},{"task":"Task 4: Empower Team Members and Stakeholders","q":"في بداية المشروع، تكتشف أن أعضاء الفريق لديهم نقاط قوة متنوعة. كيف تنظم العمل لتعظيم الإنتاجية؟","opts":["توزيع المهام بشكل عشوائي للعدالة","تحليل نقاط القوة وإسناد المهام بما يتوافق معها، مع إتاحة فرص للتطوير في مجالات جديدة","إسناد المهام بناءً على الأقدمية فقط","السماح للأعضاء باختيار أي مهمة دون توجيه"],"ans":"B","exp":"التنظيم حول نقاط القوة يعظم الإنتاجية ويعزز الالتزام. إضافة فرص تطوير محدودة في مجالات جديدة يضمن النمو دون المخاطرة بالمشروع.","id":54},{"task":"Task 4: Empower Team Members and Stakeholders","q":"ما المقصود بـ \"تمكين الفريق\" (Empowerment) في سياق PMP؟","opts":["ترك الفريق دون أي توجيه","منح الفريق الصلاحية والمسؤولية والموارد لاتخاذ القرارات وتنفيذها في حدود محددة","إعطاء الفريق رواتب أعلى","تجنب أي مساءلة للفريق"],"ans":"B","exp":"التمكين الحقيقي يجمع بين الصلاحية، المسؤولية، والموارد، ضمن حدود واضحة. ليس تخلي عن المسؤولية بل تفويض ذكي.","id":55},{"task":"Task 4: Empower Team Members and Stakeholders","q":"كيف يمكن لمدير المشروع تحديد مستوى صلاحية اتخاذ القرار المناسب لكل عضو في الفريق؟","opts":["منح الجميع نفس الصلاحيات","تقييم الكفاءة والخبرة والمسؤولية لكل عضو، وتحديد نطاقات القرار بشكل مدروس متدرج","الاحتفاظ بكل القرارات لنفسه","تفويض كل القرارات للفريق دون استثناء"],"ans":"B","exp":"تحديد صلاحيات القرار يحتاج تقييماً موضوعياً للكفاءة. التفويض الذكي المتدرج يبني الثقة ويطور القدرات تدريجياً.","id":56},{"task":"Task 4: Empower Team Members and Stakeholders","q":"أي من السلوكيات التالية تشير إلى تمكين فعال لفريق Agile؟","opts":["Scrum Master يقرر ترتيب Backlog","المطورون يخططون السبرنت ويختارون عناصر العمل بأنفسهم","صاحب المنتج يحدد كيفية تنفيذ المهام التقنية","مدير المشروع يقرر معدل العمل (Velocity)"],"ans":"B","exp":"في Scrum، فريق التطوير له ملكية كيفية إنجاز العمل ومقدار ما يلتزم به في كل سبرنت. هذا تمكين هيكلي وفقاً للإطار.","id":57},{"task":"Task 4: Empower Team Members and Stakeholders","q":"أحد أعضاء الفريق يتردد في اتخاذ القرارات وينتظر دائماً موافقتك. كيف تتصرف؟","opts":["اتخاذ القرارات نيابة عنه دائماً","دعم استقلاليته تدريجياً: تشجيعه على تقديم توصياته، التدريب على اتخاذ القرار، والاحتفاء بالقرارات الجيدة","تحويله إلى مهام لا تتطلب قرارات","تأنيبه على التردد"],"ans":"B","exp":"بناء الاستقلالية يحتاج صبراً ودعماً تدريجياً. تشجيع التوصيات والاحتفاء بالنجاحات يبني الثقة والكفاءة في اتخاذ القرار.","id":58},{"task":"Task 4: Empower Team Members and Stakeholders","q":"بعد تفويض مهمة لعضو في الفريق، اكتشفت أنه ارتكب خطأً في التنفيذ. ما أنسب رد فعل؟","opts":["سحب الصلاحية فوراً وعدم التفويض مستقبلاً","التعامل مع الخطأ كفرصة تعلم، تحليل السبب معاً، وتحسين العملية للمستقبل","إخفاء الخطأ لحماية العضو","إلقاء اللوم العلني على العضو"],"ans":"B","exp":"بيئة آمنة للتعلم من الأخطاء هي أساس الفرق عالية الأداء. سحب الصلاحية بعد كل خطأ يقتل المبادرة والإبداع.","id":59},{"task":"Task 4: Empower Team Members and Stakeholders","q":"كيف تقيّم إذا كان الفريق يمارس فعلاً المساءلة عن المهام الموكلة إليه؟","opts":["بمراقبة كل حركة بشكل دقيق","بملاحظة مدى ملكية الأعضاء للمهام، شفافيتهم في التقدم، اعترافهم بالأخطاء، وحلهم للمشاكل بشكل استباقي","بسؤال الإدارة العليا عن انطباعها","بقياس عدد الإيميلات اليومية"],"ans":"B","exp":"المؤشرات الحقيقية للمساءلة سلوكية: الملكية، الشفافية، الاعتراف بالأخطاء، والاستباقية. ليس بالرقابة المفرطة التي تقتل المساءلة الحقيقية.","id":60},{"task":"Task 4: Empower Team Members and Stakeholders","q":"في فريق متعدد التخصصات، أي ممارسة تعزز التمكين أكثر؟","opts":["السماح للفريق بتحديد كيفية تنظيم نفسه لتحقيق أهداف المشروع","فرض هيكل تنظيمي صارم من الأعلى","تعيين قائد فرعي على كل تخصص","إلزام الجميع بنفس ساعات العمل"],"ans":"A","exp":"الفرق ذاتية التنظيم (Self-Organizing) مفهوم محوري في Agile وPMI. تتيح للفريق تحديد طريقته في تحقيق الأهداف، ما يعزز الملكية والإبداع.","id":61},{"task":"Task 4: Empower Team Members and Stakeholders","q":"ما الفرق بين المسؤولية (Responsibility) والمساءلة (Accountability) في إدارة المشاريع؟","opts":["لا يوجد فرق بينهما","المسؤولية يمكن تقاسمها، أما المساءلة فعادة لشخص واحد، وهي تتعلق بالنتيجة النهائية","المساءلة للأقل خبرة فقط","المسؤولية للإدارة العليا فقط"],"ans":"B","exp":"في مصفوفة RACI، Responsible (يقوم بالعمل) قد يكون عدة أشخاص، لكن Accountable (يجيب عن النتيجة) عادة شخص واحد. التمييز جوهري للوضوح.","id":62},{"task":"Task 4: Empower Team Members and Stakeholders","q":"تواجه ضغطاً من الإدارة لاتخاذ قرارات سريعة، لكنك ترى أن التفويض للفريق أفضل على المدى الطويل. ما النهج الأنسب؟","opts":["اتخاذ كل القرارات بنفسك لإرضاء الإدارة","الموازنة: قرارات استراتيجية حرجة بسرعة، تفويض القرارات التشغيلية، وشرح الفلسفة للإدارة","تفويض كل القرارات حتى الحرجة منها","تجاهل ضغط الإدارة تماماً"],"ans":"B","exp":"القائد الناضج يوازن بين متطلبات السرعة والتمكين. التواصل الواضح مع الإدارة عن الفلسفة يبني الثقة ويحمي الفريق.","id":63},{"task":"Task 4: Empower Team Members and Stakeholders","q":"أي من الأدوات التالية تساعد في توضيح الأدوار والمساءلة في المشروع؟","opts":["WBS (هيكل تجزئة العمل)","RACI Chart (مصفوفة المسؤوليات)","Gantt Chart (مخطط جانت)","Risk Register (سجل المخاطر)"],"ans":"B","exp":"مصفوفة RACI (Responsible, Accountable, Consulted, Informed) أداة محددة لتوضيح أدوار كل شخص في كل مهمة، تمنع الغموض وتدعم المساءلة.","id":64},{"task":"Task 4: Empower Team Members and Stakeholders","q":"في مرحلة التنفيذ، يطلب أحد أعضاء الفريق صلاحية اتخاذ قرارات أكبر. كيف تستجيب؟","opts":["رفض الطلب لأنه قد يهدد سيطرتك","تقييم استعداده وكفاءته، البدء بصلاحيات متدرجة، ومراقبة النتائج","منحه كل الصلاحيات فوراً","تجاهل الطلب"],"ans":"B","exp":"التفويض المتدرج المبني على الكفاءة المثبتة يطور الأفراد ويحمي المشروع. منح الكثير دفعة واحدة قد يكون محفوفاً بالمخاطر.","id":65},{"task":"Task 4: Empower Team Members and Stakeholders","q":"ما الإجراء الذي يدل على عدم التمكين الفعّال للفريق؟","opts":["تشجيع أعضاء الفريق على حل المشكلات بأنفسهم","توفير الموارد اللازمة لاتخاذ القرارات","التدخل في كل تفصيلة وتجاوز قرارات الفريق علناً","تحديد حدود واضحة للتفويض"],"ans":"C","exp":"Micromanagement وتجاوز قرارات الفريق علناً يهدمان الثقة والتمكين. القائد الفعال يدعم قرارات فريقه ويقدم تغذية راجعة بشكل بنّاء.","id":66},{"task":"Task 4: Empower Team Members and Stakeholders","q":"كيف يمكن قياس مستوى التمكين الفعلي في الفريق؟","opts":["بعدد الاجتماعات الأسبوعية","بمدى استقلالية القرارات، سرعة حل المشكلات داخلياً، ومستوى المبادرة لدى الأعضاء","بحجم التقارير المكتوبة","بعدد ساعات العمل"],"ans":"B","exp":"مؤشرات التمكين سلوكية: استقلالية القرار، سرعة حل المشاكل ذاتياً، والمبادرة. هذه أكثر دلالة من المقاييس الإجرائية.","id":67},{"task":"Task 4: Empower Team Members and Stakeholders","q":"في فريق يعمل عن بُعد، كيف تعزز التمكين بشكل خاص؟","opts":["زيادة الرقابة عبر برامج مراقبة الشاشة","وضع أهداف واضحة، نتائج قابلة للقياس، أدوات تعاون فعالة، والثقة في تنفيذ الفريق","إلزام الفريق بساعات حضور افتراضية صارمة","اجتماعات يومية طويلة لمراقبة الجميع"],"ans":"B","exp":"الفرق عن بُعد تزدهر بالنتائج لا الرقابة. وضوح الأهداف، الأدوات المناسبة، والثقة هي ركائز تمكين الفرق الموزعة.","id":68},{"task":"Task 5: Ensure Team Training","q":"في بداية مشروع جديد، كيف تحدد احتياجات التدريب للفريق بشكل منهجي؟","opts":["افتراض أن الفريق لا يحتاج تدريباً ما دام لديه خبرة سابقة","تحليل فجوة بين الكفاءات المطلوبة للمشروع والكفاءات الحالية للفريق","تقديم تدريب عام للجميع","السؤال عن التدريبات المفضلة فقط"],"ans":"B","exp":"تحليل الفجوة (Gap Analysis) هو النهج المنهجي. يحدد الفارق بين الوضع الحالي والمطلوب، ويوجه قرارات التدريب بدقة.","id":69},{"task":"Task 5: Ensure Team Training","q":"بعد تحديد احتياجات التدريب، أي عامل يجب مراعاته عند اختيار الخيار التدريبي؟","opts":["التكلفة فقط","الموازنة بين الفعالية، التكلفة، المدة، أسلوب التعلم المناسب، وتوافر الموارد","ما هو متاح مجاناً فقط","اختيار الأطول مدة لأنه أعمق"],"ans":"B","exp":"اختيار التدريب يحتاج موازنة متعددة الأبعاد. الأرخص أو الأطول ليس بالضرورة الأفضل، والتوافق مع أساليب التعلم يحسن النتائج.","id":70},{"task":"Task 5: Ensure Team Training","q":"كيف يمكن قياس فعالية التدريب الذي قدم لفريق المشروع؟","opts":["بعدد ساعات التدريب المكتملة","باستخدام نموذج كيركباتريك: ردود الفعل، التعلم، السلوك، والنتائج","بمدى رضا الإدارة عن إجراء التدريب","بحضور كل الجلسات"],"ans":"B","exp":"نموذج كيركباتريك معيار شائع لتقييم التدريب: المستويات الأربعة تقيس من رضى المشاركين إلى الأثر الفعلي على نتائج العمل.","id":71},{"task":"Task 5: Ensure Team Training","q":"يطلب أحد أعضاء الفريق تدريباً متقدماً غير ضروري للمشروع الحالي لكنه مفيد لتطوره المهني. كيف تتعامل؟","opts":["رفض الطلب لعدم ارتباطه بالمشروع","تقييم القيمة طويلة الأمد، الموازنة مع الميزانية، واستكشاف بدائل (دعم جزئي، تدريب لاحق)","الموافقة على كل طلبات التدريب","إحالته للموارد البشرية فقط"],"ans":"B","exp":"دعم تطور الأفراد يعزز الولاء والاحتفاظ بالكفاءات. الموازنة الذكية بين احتياجات المشروع وتطور الأفراد ممارسة قيادية حكيمة.","id":72},{"task":"Task 5: Ensure Team Training","q":"كيف تخصص الموارد للتدريب بشكل فعال؟","opts":["تخصيص ميزانية صغيرة لكل عضو بالتساوي","تخطيط ميزانية التدريب في خطة الموارد، تحديد الأولويات بناءً على فجوات حرجة، وتتبع الإنفاق","تأجيل التدريب حتى نهاية المشروع","تجنب التدريب لتوفير الميزانية"],"ans":"B","exp":"تخصيص موارد التدريب جزء من تخطيط الموارد. التركيز على الفجوات الحرجة يضمن أكبر عائد على الاستثمار التدريبي.","id":73},{"task":"Task 5: Ensure Team Training","q":"ما أنسب نوع تدريب لفريق ينتقل من نهج تنبئي إلى نهج هجين؟","opts":["تدريب تقني صرف فقط","تدريب يشمل مبادئ Agile، التطبيقات العملية، ورش محاكاة، وإرشاد من ممارس خبير","محاضرة نظرية لمدة يوم واحد","كتيب يقرأه الفريق بنفسه"],"ans":"B","exp":"التحول المنهجي يحتاج تعلم متعدد الأبعاد: مفاهيم، تطبيق، ومحاكاة، مع دعم مستمر. التدريب القصير لا يكفي لتغيير العقلية.","id":74},{"task":"Task 5: Ensure Team Training","q":"بعد التدريب، كيف تتحقق من تطبيق المهارات الجديدة في العمل الفعلي؟","opts":["افتراض التطبيق بمجرد انتهاء التدريب","متابعة دورية، توفير فرص تطبيق، وتغذية راجعة، وقياس مؤشرات الأداء بعد التدريب","اختبار نظري فقط","السؤال عن انطباع المتدربين"],"ans":"B","exp":"نقل التعلم إلى العمل (Transfer of Learning) يتطلب فرص تطبيق ومتابعة. بدون ذلك، يضيع معظم أثر التدريب خلال شهور.","id":75},{"task":"Task 5: Ensure Team Training","q":"أي نوع من التدريب أكثر فاعلية في تطوير المهارات الناعمة (Soft Skills)؟","opts":["محاضرات نظرية فقط","تجارب تفاعلية، ورش محاكاة، تمثيل أدوار، وتغذية راجعة 360 درجة","قراءة الكتب فقط","اختبارات إلكترونية"],"ans":"B","exp":"المهارات الناعمة تكتسب بالممارسة والتأمل. أساليب التعلم التجريبية أكثر فاعلية من المحاضرات النظرية.","id":76},{"task":"Task 5: Ensure Team Training","q":"ما الأولوية عند تحديد كفاءات التدريب لفريق متعدد التخصصات؟","opts":["تدريب الجميع على كل التخصصات","تحديد الكفاءات الأساسية لكل دور، وكفاءات مشتركة (تعاون، تواصل)، وكفاءات إضافية اختيارية","تدريب على التخصص الأكبر فقط","تأجيل التدريب لحين ظهور المشاكل"],"ans":"B","exp":"نموذج كفاءات منظم (أساسية، مشتركة، اختيارية) يوجه الاستثمار التدريبي بطريقة عقلانية ويغطي احتياجات الأدوار المختلفة.","id":77},{"task":"Task 5: Ensure Team Training","q":"يكتشف مدير المشروع أن أحد الأعضاء يفتقر لمهارة حرجة في منتصف المشروع. ما أفضل تصرف؟","opts":["إخراجه من المشروع فوراً","تقييم الفجوة، خيارات سريعة (إرشاد مكثف، تدريب مكثف، إقران مع زميل خبير)، ومراقبة التقدم","تجاهل الفجوة","إعادة توزيع كل المهام"],"ans":"B","exp":"خيارات التعلم السريع (Pair Programming, Mentoring مكثف) أكثر فاعلية في الأزمات من إخراج الموظف أو التجاهل.","id":78},{"task":"Task 5: Ensure Team Training","q":"كيف يمكن لمدير المشروع توثيق نتائج التدريب للاستفادة منها في مشاريع مستقبلية؟","opts":["لا حاجة للتوثيق","توثيق الفجوات، الخيارات المختارة، الميزانية، والنتائج كجزء من الدروس المستفادة في سجل الأصول التنظيمية","توثيق فقط الجوانب السلبية","إرسال بريد إلكتروني للراعي فقط"],"ans":"B","exp":"توثيق التدريب في الدروس المستفادة وأصول العمليات التنظيمية يبني ذاكرة مؤسسية ويحسن قرارات التدريب المستقبلية.","id":79},{"task":"Task 5: Ensure Team Training","q":"في فريق Agile، ما أفضل نهج لبناء قدرات الفريق على مر الزمن؟","opts":["تدريب رسمي مرة كل سنة فقط","خليط من: التعلم في السبرنت (Slack time)، تبادل المعرفة الداخلي، مجتمعات الممارسة، وتدريب مستهدف","اعتماد كامل على التدريب الخارجي","تجنب أي تدريب لتسريع العمل"],"ans":"B","exp":"بناء القدرات في Agile يحدث بشكل مستمر: تعلم داخلي، تبادل خبرات، ووقت مخصص للتطوير. هذا أكثر استدامة من التدريب المتقطع.","id":80},{"task":"Task 6: Build a Team","q":"ما الخطوة الأولى في بناء فريق فعّال لمشروع جديد؟","opts":["البدء بإسناد المهام مباشرة","تقييم مهارات أصحاب المصلحة المتاحين واستنتاج متطلبات الموارد البشرية للمشروع","إعداد جدول زمني","اختيار أدوات العمل"],"ans":"B","exp":"بناء الفريق يبدأ بفهم متطلبات المشروع وتقييم المهارات المتاحة. هذا يوجه قرارات التوظيف والتدريب والتفويض.","id":81},{"task":"Task 6: Build a Team","q":"كيف يمكن تقييم مهارات أصحاب المصلحة الذين قد يساهمون في المشروع؟","opts":["الاعتماد على السير الذاتية فقط","مزيج من السيرة الذاتية، المقابلات، الأداء السابق، وتقييم الكفاءات بأدوات موضوعية","السؤال العام عن قدراتهم","افتراض الكفاءة بناءً على المنصب"],"ans":"B","exp":"تقييم متعدد المصادر يعطي صورة أدق من السيرة الذاتية وحدها. الأداء السابق وتقييمات الكفاءة الموضوعية مؤشرات قوية.","id":82},{"task":"Task 6: Build a Team","q":"بعد بدء المشروع، تكتشف أن مهارات الفريق لم تعد كافية مع تطور المتطلبات. ما الإجراء؟","opts":["الاستمرار بالمهارات الحالية فقط","إجراء تقييم جديد لمهارات الفريق، تحديث الفجوات، تجديد المهارات (تدريب، إضافة أعضاء، استشاريين)","إخراج الأعضاء غير المؤهلين فقط","تأخير المشروع حتى تتطور المهارات تلقائياً"],"ans":"B","exp":"التقييم المستمر لمهارات الفريق مقابل الاحتياجات المتغيرة ضروري. مرونة الفريق تأتي من التحديث المستمر للمهارات بطرق متعددة.","id":83},{"task":"Task 6: Build a Team","q":"أي من المراحل التالية في نموذج تاكمان (Tuckman) يصبح فيها الفريق منتجاً بأعلى كفاءة؟","opts":["Forming","Storming","Norming","Performing"],"ans":"D","exp":"Performing هي مرحلة الذروة الإنتاجية حيث يعمل الفريق بانسجام ودون الحاجة لإشراف مكثف. الوصول إليها يتطلب اجتياز المراحل السابقة.","id":84},{"task":"Task 6: Build a Team","q":"أحد كبار أعضاء الفريق سيغادر قبل انتهاء المشروع. كيف تحافظ على استمرارية المعرفة؟","opts":["البحث عن بديل مكافئ في اللحظة الأخيرة","تخطيط لنقل المعرفة (توثيق، إرشاد، تدريب البديل، مراجعات مشتركة) قبل المغادرة بفترة كافية","تجاهل الموضوع حتى يغادر فعلياً","محاولة منعه من المغادرة"],"ans":"B","exp":"نقل المعرفة المنظم قبل المغادرة يحافظ على استمرارية المشروع. يشمل التوثيق الصريح، التدريب، والإرشاد المكثف.","id":85},{"task":"Task 6: Build a Team","q":"في تكوين فريق متعدد الثقافات، أي ممارسة تساعد على بنائه بفعالية؟","opts":["تجاهل الاختلافات الثقافية","بناء الوعي الثقافي، وضع قواعد عمل مشتركة محترمة للاختلافات، وأنشطة بناء فريق","فصل الفريق إلى مجموعات حسب الثقافة","فرض ثقافة موحدة"],"ans":"B","exp":"إدارة التنوع الثقافي بذكاء تحول الاختلافات إلى نقاط قوة. الوعي والقواعد المشتركة والأنشطة المشتركة تبني فريقاً مترابطاً.","id":86},{"task":"Task 6: Build a Team","q":"ما الفرق بين فريق المشروع المخصص (Dedicated) والفريق ذو التفرغ الجزئي (Part-Time) من منظور إدارة المشاريع؟","opts":["لا فرق بينهما","المخصص يلتزم بـ 100% للمشروع مما يسهل التركيز، بينما الجزئي يحتاج إدارة دقيقة للأولويات والوقت","الجزئي أكثر إنتاجية دائماً","المخصص أرخص دائماً"],"ans":"B","exp":"الفهم العميق لطبيعة كل نموذج يوجه استراتيجيات الإدارة. الفرق الجزئية تحتاج إدارة احترافية للأولويات وتنسيقاً مع المديرين الوظيفيين.","id":87},{"task":"Task 6: Build a Team","q":"كيف تستنتج متطلبات الموارد البشرية للمشروع بشكل دقيق؟","opts":["الاعتماد على الحدس فقط","تحليل WBS، تقدير الجهد لكل مهمة، تحديد المهارات المطلوبة، ومراجعة الدروس المستفادة من مشاريع مشابهة","نسخ تركيبة مشروع سابق دون مراجعة","طلب أكبر عدد ممكن من الأعضاء"],"ans":"B","exp":"استنتاج متطلبات الموارد يبدأ من WBS وتقدير الجهد، مع الاستفادة من البيانات التاريخية. هذا أكثر دقة من الحدس أو النسخ.","id":88},{"task":"Task 6: Build a Team","q":"في فريق Agile، ما الحجم الموصى به للفريق لتحقيق أعلى فاعلية؟","opts":["أكبر عدد ممكن لتسريع العمل","عادة بين 3 و 9 أعضاء (قاعدة 7±2)","شخص واحد فقط لتقليل التواصل","20 شخصاً على الأقل"],"ans":"B","exp":"أبحاث الفرق وممارسات Scrum تشير إلى أن 3-9 أعضاء (مع تفضيل ~5-7) هو الحجم الأمثل لتوازن التواصل والقدرة الإنتاجية.","id":89},{"task":"Task 6: Build a Team","q":"كيف يمكن لمدير المشروع تعزيز التماسك بين أعضاء فريق جديد؟","opts":["تجنب التفاعل غير الرسمي للحفاظ على الجدية","أنشطة بناء فريق هادفة، اجتماع إطلاق فعّال، فرص للتعاون على مهام مشتركة، واحتفاء بالنجاحات","زيادة الرقابة الإدارية","تقليل التواصل لتقليل النزاعات"],"ans":"B","exp":"التماسك يحتاج فرصاً للتفاعل والتعاون. الأنشطة الهادفة والنجاحات المشتركة تبني الثقة والروابط بشكل طبيعي.","id":90},{"task":"Task 6: Build a Team","q":"أي من العوامل التالية ليس له تأثير مباشر على متطلبات تشكيل فريق المشروع؟","opts":["نطاق المشروع وتعقيده","الميزانية والجدول الزمني","هواية مدير المشروع الشخصية","المهارات والخبرات المطلوبة"],"ans":"C","exp":"تشكيل الفريق يحدد بمتطلبات المشروع الموضوعية (نطاق، ميزانية، مهارات). تفضيلات المدير الشخصية ليست عاملاً مهنياً.","id":91},{"task":"Task 6: Build a Team","q":"ما الخطوة الأولى في تخطيط نقل المعرفة من فريق المشروع المنتهي إلى فريق العمليات؟","opts":["تحديد المحتوى الذي يجب نقله، الجمهور، والقنوات، والجدول الزمني","إرسال جميع وثائق المشروع كملف ضخم","عقد اجتماع واحد قصير","ترك الفريق الجديد ليكتشف بنفسه"],"ans":"A","exp":"نقل المعرفة المنظم يبدأ بتخطيط واضح للمحتوى والجمهور والقنوات. هذا يضمن فعالية النقل ويمنع فقدان المعرفة الحرجة.","id":92},{"task":"Task 6: Build a Team","q":"في فريق هجين (داخلي وخارجي/استشاريين)، أي ممارسة تساعد على بناء التماسك؟","opts":["معاملة الاستشاريين كأعضاء كاملين في الفريق ضمن حدود تعاقدية واضحة","عزل الاستشاريين عن الاجتماعات الداخلية","إخفاء معلومات المشروع عن الاستشاريين","تجنب أي تفاعل غير ضروري"],"ans":"A","exp":"الاستشاريون منتجون أكثر عندما يُدمجون في الفريق بشكل مهني، مع الحفاظ على الحدود التعاقدية والمعلومات الحساسة.","id":93},{"task":"Task 6: Build a Team","q":"كيف تتحقق من جاهزية فريقك للانتقال إلى مرحلة جديدة من المشروع؟","opts":["افتراض الجاهزية مرور الوقت","تقييم المهارات الحالية مقابل متطلبات المرحلة القادمة، التحقق من الأدوات، وتجهيز التدريب اللازم","تجاهل المتطلبات الجديدة","البدء بالمرحلة فوراً ومعالجة المشاكل لاحقاً"],"ans":"B","exp":"التخطيط الاستباقي لكل مرحلة يضمن انتقالاً سلساً. تقييم المهارات والأدوات والتدريب يقلل من اضطرابات الانتقال.","id":94},{"task":"Task 6: Build a Team","q":"أي من الأنشطة التالية ليست من ممارسات بناء الفريق الفعّال؟","opts":["اجتماع إطلاق للمشروع","إنشاء عقد فريق تعاوني","السماح بالغموض في الأدوار لتشجيع المرونة","أنشطة اجتماعية وأنشطة بناء فريق منتظمة"],"ans":"C","exp":"الغموض في الأدوار يخلق نزاعات وعدم كفاءة. الوضوح في الأدوار (مع مرونة محددة) أساس الفرق الفعالة.","id":95},{"task":"Task 7: Remove Impediments","q":"ما المقصود بـ \"Impediment\" في سياق إدارة المشاريع؟","opts":["خطر محتمل قد يحدث في المستقبل","أي عائق يمنع أو يبطئ تقدم الفريق ويحتاج إلى إزالة","نزاع شخصي بين الأعضاء","تأخير مقصود من العميل"],"ans":"B","exp":"العوائق (Impediments) هي مشاكل ملموسة حالية تعرقل الفريق، تختلف عن المخاطر (احتمالية مستقبلية). إزالتها مسؤولية القائد الخادم.","id":96},{"task":"Task 7: Remove Impediments","q":"في Daily Standup، يعلن أحد المطورين عن عائق يبطئ عمله. ما أنسب تصرف لـ Scrum Master؟","opts":["إخباره بأن يحله بنفسه","توثيق العائق، تحديد الأولوية، استخدام شبكة العلاقات لإزالته، ومتابعة الحل","تأجيل النقاش لما بعد السبرنت","نقل العائق للإدارة العليا مباشرة"],"ans":"B","exp":"إزالة العوائق مسؤولية محورية لـ Scrum Master/مدير المشروع. التوثيق، الأولوية، والتنفيذ مع المتابعة هي العملية الصحيحة.","id":97},{"task":"Task 7: Remove Impediments","q":"كيف يحدد مدير المشروع \"العائق الحرج\" الذي يستحق الأولوية القصوى؟","opts":["أي عائق يذكره الفريق","العائق الذي يهدد تسليم القيمة، الجدول الزمني، أو يعطل أعضاء متعددين","العائق الذي يطلبه أكبر صاحب مصلحة","العائق الأقدم في القائمة"],"ans":"B","exp":"تحديد العوائق الحرجة يعتمد على الأثر: على القيمة، الجدول، وعدد المتأثرين. هذا أكثر موضوعية من السن أو ضغط الأصحاب.","id":98},{"task":"Task 7: Remove Impediments","q":"العائق يتطلب قراراً من إدارة قسم آخر لا تقع تحت سلطتك. كيف تتصرف؟","opts":["الاستسلام لأن الأمر خارج سلطتك","استخدام شبكة علاقاتك، التواصل مع نظرائك في القسم الآخر، وعرض الأثر على المشروع، والتصعيد عند الحاجة","تجاهل العائق","إلقاء اللوم على الإدارة الأخرى علناً"],"ans":"B","exp":"بناء واستخدام شبكة العلاقات (Networking) جزء أساسي من إزالة العوائق. التصعيد يأتي بعد محاولات الحل التشاركية.","id":99},{"task":"Task 7: Remove Impediments","q":"ما الفرق بين العائق (Impediment) والمشكلة (Issue) والمخاطرة (Risk)؟","opts":["لا فرق بينهم","العائق يمنع تقدم العمل حالياً، المشكلة حدث وقع، والمخاطرة حدث محتمل في المستقبل","المخاطرة هي نفسها العائق","العائق يعني فقط النقص في الموارد"],"ans":"B","exp":"التمييز الدقيق مهم: المخاطر (Risks) محتملة، المشاكل (Issues) متحققة، والعوائق (Impediments) محددة جداً وتعطل الفريق الآن.","id":100},{"task":"Task 7: Remove Impediments","q":"كيف يحافظ مدير المشروع على متابعة العوائق التي تم \"حلها\"؟","opts":["افتراض عدم عودتها بعد الحل","متابعة دورية، التحقق من بقاء الحل فعالاً، ومراقبة عوائق مماثلة قد تظهر","تجاهلها بعد الحل","إعادة فتحها كل أسبوع"],"ans":"B","exp":"إعادة التقييم المستمر للعوائق تضمن استدامة الحلول. العوائق قد تعود بأشكال جديدة، والمتابعة الدورية تكتشف ذلك مبكراً.","id":101},{"task":"Task 7: Remove Impediments","q":"يواجه الفريق عائقاً تقنياً معقداً يحتاج خبرة خارجية. ما الخيار الأفضل؟","opts":["ترك الفريق يحاول حله مهما طال الوقت","تقييم الخيارات: استشاري خارجي، تدريب مكثف، التعاون مع فريق آخر، أو بدائل تقنية","إلغاء المهمة المتأثرة","تجاهل العائق"],"ans":"B","exp":"تقييم خيارات متعددة قبل القرار يضمن الحل الأمثل. اعتماد خبرة خارجية أحياناً أكثر كفاءة من إجبار الفريق على إعادة اختراع العجلة.","id":102},{"task":"Task 7: Remove Impediments","q":"أي ممارسة تساعد على اكتشاف العوائق مبكراً؟","opts":["الانتظار حتى يبلغ الفريق عنها رسمياً","اجتماعات قصيرة منتظمة (Stand-ups)، قناة مفتوحة للتواصل، وثقافة شفافية تشجع الإفصاح المبكر","تجنب الاجتماعات لتوفير الوقت","الاعتماد على التقارير الشهرية"],"ans":"B","exp":"الاكتشاف المبكر يتطلب آليات تواصل متكررة وثقافة آمنة للإفصاح. التقارير الشهرية بطيئة جداً للعوائق التشغيلية.","id":103},{"task":"Task 7: Remove Impediments","q":"بعد إزالة عائق، ما الإجراء التوثيقي المناسب؟","opts":["لا حاجة للتوثيق بعد الحل","توثيق العائق، السبب الجذري، الحل المتبع، الدروس المستفادة، والوقت المستغرق في سجل العوائق","حذف العائق من السجل","إرسال بريد إلكتروني عام للجميع"],"ans":"B","exp":"توثيق العوائق وحلولها يبني معرفة مؤسسية ويساعد في معالجة عوائق مشابهة مستقبلاً بشكل أسرع.","id":104},{"task":"Task 7: Remove Impediments","q":"أحد أعضاء الفريق يحاول حل عائق بنفسه دون إبلاغك. اكتشفت ذلك بعد أسبوع وقد تأخر العمل. كيف تتصرف؟","opts":["معاقبته على عدم الإبلاغ","محادثة بنّاءة لفهم لماذا لم يبلغ، تعزيز ثقافة الإفصاح، وتوضيح الأدوار في معالجة العوائق","تجاهل الموضوع","إخراجه من الفريق"],"ans":"B","exp":"السلوك يشير إلى مشكلة في ثقافة الفريق أو تصور الدور. الحوار البنّاء يعالج السبب الجذري ويعزز الإفصاح المستقبلي.","id":105},{"task":"Task 7: Remove Impediments","q":"في مشروع كبير، يواجه الفريق عوائق متعددة في وقت واحد. كيف يحدد مدير المشروع الأولويات؟","opts":["معالجتها بترتيب وصولها","تقييم الأثر (مالي، جدول، جودة) والإلحاح، استخدام مصفوفة Impact/Urgency لتحديد الأولوية","ترك الفريق يقرر بنفسه","تأجيلها جميعاً حتى تتضح الصورة"],"ans":"B","exp":"أدوات تحديد الأولويات الموضوعية (Impact/Urgency Matrix) تضمن استخدام الموارد المحدودة بشكل أمثل.","id":106},{"task":"Task 7: Remove Impediments","q":"ما دور قائد فريق Agile (Scrum Master) الأساسي في إزالة العوائق؟","opts":["حل كل عائق بنفسه دون مساعدة","تيسير الإزالة بحماية الفريق، استخدام شبكة العلاقات، وتمكين الفريق من حل العوائق التي يقدر عليها","تجاهل العوائق التي لا تتعلق بـ Scrum","نقل كل العوائق إلى صاحب المنتج"],"ans":"B","exp":"Scrum Master قائد خادم: يحمي الفريق، يستخدم شبكته لإزالة العوائق التنظيمية، ويمكّن الفريق من حل ما يستطيع داخلياً.","id":107},{"task":"Task 7: Remove Impediments","q":"تكرر ظهور نفس العائق في عدة سبرنتات. ما الإجراء الصحيح؟","opts":["حله بنفس الطريقة كل مرة","تحليل السبب الجذري (مثل 5 Whys)، ومعالجة المنشأ الحقيقي بدل الأعراض المتكررة","تجاهل العائق","إلقاء اللوم على الفريق"],"ans":"B","exp":"العوائق المتكررة علامة على سبب جذري أعمق. تقنيات مثل 5 Whys أو Fishbone Diagram تكشف السبب الحقيقي وتوجه حلاً جذرياً.","id":108},{"task":"Task 7: Remove Impediments","q":"يطلب صاحب المنتج إضافة عمل إضافي مما يخلق عائق إضافة حمل على الفريق. ما أفضل تصرف؟","opts":["قبول العمل لتجنب الصراع","تيسير حوار شفاف عن الأثر، عرض الخيارات (إعادة ترتيب الأولويات، إزالة عناصر أقل أهمية)، والوصول لاتفاق","رفض الطلب بشكل قاطع","تكليف الفريق بساعات إضافية"],"ans":"B","exp":"الشفافية في عرض المقايضات تمكن صاحب المنتج من اتخاذ قرار مستنير. تحميل الفريق فوق طاقته يضر بالاستدامة والجودة.","id":109},{"task":"Task 8: Negotiate Project Agreements","q":"قبل الدخول في مفاوضات اتفاقية كبيرة مع مورد، ما الإجراء الأكثر أولوية؟","opts":["البدء بالاجتماع مباشرة لتوفير الوقت","تحليل حدود التفاوض، تحديد الأولويات والأهداف النهائية، وفهم موقف الطرف الآخر","تحديد سعر منخفض جداً كموقف ابتدائي","تجنب التحضير لإظهار المرونة"],"ans":"B","exp":"التحضير الجيد هو 80% من نجاح التفاوض. تحليل الحدود (ZOPA, BATNA)، الأولويات، وفهم الطرف الآخر يخلق أساساً قوياً.","id":110},{"task":"Task 8: Negotiate Project Agreements","q":"ما المقصود بـ BATNA في التفاوض؟","opts":["أفضل عرض مبدئي تقدمه","Best Alternative To a Negotiated Agreement - أفضل بديل لديك إذا فشل التفاوض","أقل سعر يمكنك قبوله","اسم عضو الفريق المسؤول عن التفاوض"],"ans":"B","exp":"BATNA هو موقفك البديل إذا لم تنجح المفاوضات. معرفته بدقة يحدد متى تتفاوض ومتى تنسحب، ويعطيك قوة موضوعية.","id":111},{"task":"Task 8: Negotiate Project Agreements","q":"أثناء مفاوضات عقد، يصر المورد على بنود لا تتوافق مع متطلبات المشروع. ما الاستراتيجية الأنسب؟","opts":["قبول البنود لإنهاء المفاوضات","التركيز على المصالح وراء المواقف، طرح خيارات متعددة لكسب المنفعة المشتركة، والاستناد إلى معايير موضوعية","الانسحاب فوراً","تهديد المورد بالعقاب القانوني"],"ans":"B","exp":"نموذج هارفارد للتفاوض المبني على المبادئ: التركيز على المصالح لا المواقف، الخيارات الإبداعية، والمعايير الموضوعية، يقود إلى اتفاقات أفضل.","id":112},{"task":"Task 8: Negotiate Project Agreements","q":"كيف يمكن لمدير المشروع التحقق من تحقيق أهداف التفاوض في الاتفاقية النهائية؟","opts":["الاعتماد على ذاكرته بعد التوقيع","مراجعة الاتفاقية بدقة مقابل قائمة الأهداف المحددة قبل التفاوض، وتوثيق أي فجوات أو مخاطر متبقية","السؤال عن انطباعات الفريق","افتراض أن المحامي تحقق من كل شيء"],"ans":"B","exp":"المراجعة المنهجية مقابل الأهداف الأصلية تضمن عدم ضياع متطلبات حرجة في زحمة التفاوض. توثيق الفجوات مهم لإدارة المخاطر.","id":113},{"task":"Task 8: Negotiate Project Agreements","q":"أي نوع من العقود يحوّل أعلى قدر من المخاطرة إلى البائع (Seller)؟","opts":["عقد التكلفة الزائدة الرسوم الثابتة (CPFF)","عقد السعر الثابت (FFP)","عقد الوقت والمواد (T&M)","عقد التكلفة الزائدة المكافأة (CPAF)"],"ans":"B","exp":"في FFP، يلتزم البائع بسعر ثابت مهما زادت التكاليف، فيتحمل مخاطر تجاوز التكلفة. CPFF و T&M يضعان المخاطر على المشتري بشكل أكبر.","id":114},{"task":"Task 8: Negotiate Project Agreements","q":"خلال المفاوضات، يقدم الطرف الآخر طلباً غير متوقع يحتاج وقتاً للتحليل. ما أفضل تصرف؟","opts":["الرد فوراً لإظهار الحسم","طلب استراحة لتحليل الطلب، التشاور مع أصحاب القرار، والعودة برد مدروس","رفضه فوراً دون نقاش","قبوله مباشرة لإظهار حسن النية"],"ans":"B","exp":"طلب الوقت للتحليل ممارسة مهنية محترمة. الردود السريعة تحت الضغط قد تؤدي إلى تنازلات غير ضرورية أو تفويت فرص.","id":115},{"task":"Task 8: Negotiate Project Agreements","q":"ما الفرق بين التفاوض التوزيعي (Distributive) والتفاوض التكاملي (Integrative)؟","opts":["لا فرق بينهما","التوزيعي يفترض كعكة ثابتة (win-lose)، بينما التكاملي يبحث عن خلق قيمة لكلا الطرفين (win-win)","التوزيعي للعقود الصغيرة فقط","التكاملي يستخدم فقط في الحكومات"],"ans":"B","exp":"التفاوض التكاملي يبحث عن مصالح مشتركة وخلق قيمة، وهو المفضل في علاقات طويلة الأمد. التوزيعي مناسب لصفقات لمرة واحدة.","id":116},{"task":"Task 8: Negotiate Project Agreements","q":"في مفاوضات مع فريقك حول الالتزامات الزمنية لسبرنت قادم، ما النهج الأمثل؟","opts":["فرض ما تريد كمدير","حوار مفتوح حول السعة الفعلية، استخدام بيانات تاريخية، والوصول لالتزام جماعي قابل للتحقيق","قبول كل ما يقترحه الفريق دون نقاش","تفويض القرار لصاحب المنتج فقط"],"ans":"B","exp":"في Agile، الفريق هو من يلتزم بناءً على سعته الفعلية. القائد يسهل بناءً على بيانات موضوعية، لا يفرض ولا يستسلم.","id":117},{"task":"Task 8: Negotiate Project Agreements","q":"في التفاوض، يستخدم الطرف الآخر تكتيك \"Take it or Leave it\". كيف تتعامل؟","opts":["القبول الفوري لتجنب فشل المفاوضات","عدم الاستجابة لتكتيكات الضغط، إعادة التركيز على المصالح والمعايير الموضوعية، والاستعداد للانسحاب لـ BATNA","إظهار الغضب والانسحاب","تقديم تنازلات إضافية"],"ans":"B","exp":"التعرف على التكتيكات وعدم الانجراف معها هو علامة المفاوض المحترف. الاستناد إلى BATNA يمنحك القوة لرفض الضغط غير المبرر.","id":118},{"task":"Task 8: Negotiate Project Agreements","q":"كيف يحدد مدير المشروع \"الأهداف النهائية\" قبل التفاوض؟","opts":["بناءً على ما يفكر فيه شخصياً","بالتشاور مع أصحاب المصلحة، تحديد المتطلبات الأساسية vs الرغبات، ووضع حدود واقعية مدعومة بالبيانات","بمحاولة الحصول على كل شيء","بتجنب تحديد أهداف لإبقاء المرونة"],"ans":"B","exp":"الأهداف الواضحة المبنية على المتطلبات والبيانات تمنحك بوصلة في التفاوض. التمييز بين \"يجب\" و \"يفضل\" يساعد في التنازل الذكي.","id":119},{"task":"Task 8: Negotiate Project Agreements","q":"أثناء التفاوض على عقد كبير، يطلب الطرف الآخر تعديلات تؤثر على نطاق المشروع. ما الإجراء الأنسب؟","opts":["قبول التعديلات لإنهاء المفاوضات","تقييم التأثير على الجدول، الميزانية، والجودة، التشاور مع الراعي، والتفاوض على المقايضات المناسبة","رفض كل التعديلات تلقائياً","إيقاف المفاوضات بشكل دائم"],"ans":"B","exp":"تغييرات النطاق تتطلب تقييماً شاملاً للأثر. التفاوض على المقايضات (سعر، وقت، نطاق) أكثر فاعلية من القبول أو الرفض الأعمى.","id":120},{"task":"Task 8: Negotiate Project Agreements","q":"ما أهمية بناء العلاقات (Rapport) في التفاوض؟","opts":["غير مهم، التفاوض موضوعي بحت","بناء الثقة والاحترام يخلق بيئة تعاونية تسهل الوصول إلى حلول مرضية للطرفين","يجعل التفاوض أصعب","يعرّضك للتلاعب فقط"],"ans":"B","exp":"العلاقات الإيجابية تسهل التواصل الصريح وحل المشاكل المشتركة. حتى في التفاوضات الصعبة، الاحترام المتبادل يحسن النتائج.","id":121},{"task":"Task 8: Negotiate Project Agreements","q":"بعد التوصل إلى اتفاقية، ما الإجراء الأكثر أهمية؟","opts":["البدء فوراً بالتنفيذ","توثيق الاتفاقية بدقة، توضيح المسؤوليات والمعالم، ومراجعة المخاطر، والحصول على الموافقات الرسمية","إخبار الفريق فقط شفهياً","تأجيل التوثيق لما بعد التنفيذ"],"ans":"B","exp":"التوثيق الواضح ضروري لتجنب النزاعات لاحقاً. اتفاقيات شفهية تخلق غموضاً وتؤدي إلى مشاكل عند التنفيذ.","id":122},{"task":"Task 8: Negotiate Project Agreements","q":"أي من العبارات التالية تصف استراتيجية تفاوض فعالة؟","opts":["إخفاء جميع المعلومات عن الطرف الآخر دائماً","موازنة بين المصالح المشتركة والمتنافسة، استكشاف خيارات قبل الحكم، واستخدام معايير موضوعية للتقييم","اعتبار التفاوض حرباً يجب الفوز بها","تقديم أكبر تنازل في البداية"],"ans":"B","exp":"التفاوض الفعال علم وفن: يحتاج هيكلاً (مصالح، خيارات، معايير) ومرونة. التطرف في أي اتجاه يضعف النتائج.","id":123},{"task":"Task 9: Collaborate with Stakeholders","q":"ما الخطوة الأولى في بناء استراتيجية تعاون فعالة مع أصحاب المصلحة؟","opts":["إرسال تحديثات أسبوعية للجميع","تقييم احتياجات الإشراك لكل صاحب مصلحة بناءً على تأثيره، اهتمامه، وتوقعاته","عقد اجتماع شامل لكل الأطراف","افتراض أن جميع أصحاب المصلحة لديهم نفس الاحتياجات"],"ans":"B","exp":"التقييم الفردي لكل صاحب مصلحة هو أساس استراتيجية إشراك مفصلة. النهج الموحد للجميع غير فعال.","id":124},{"task":"Task 9: Collaborate with Stakeholders","q":"اكتشفت أن توقعات صاحب مصلحة كبير لا تتوافق مع أهداف المشروع. ما أفضل تصرف؟","opts":["تجاهل التضارب على أمل اختفائه","حوار مباشر لفهم توقعاته، توضيح أهداف المشروع، والبحث عن مواءمة بشكل تعاوني","تجنب صاحب المصلحة","تغيير أهداف المشروع لإرضائه"],"ans":"B","exp":"مواءمة التوقعات تتطلب حواراً صريحاً. تجاهل التضارب يؤدي إلى مفاجآت سيئة. تغيير الأهداف دون مبرر يضر بالمشروع.","id":125},{"task":"Task 9: Collaborate with Stakeholders","q":"كيف يبني مدير المشروع الثقة مع أصحاب المصلحة بشكل فعّال؟","opts":["إخبارهم بما يريدون سماعه","الشفافية المستمرة، الوفاء بالالتزامات، الاستماع الفعال، والاستجابة للمخاوف بصدق","تجنب الأخبار السيئة","إخفاء التحديات لتجنب القلق"],"ans":"B","exp":"الثقة تبنى بمصداقية مستدامة: شفافية حتى في الأخبار السيئة، احترام الالتزامات، والاستماع الحقيقي.","id":126},{"task":"Task 9: Collaborate with Stakeholders","q":"اكتشفت أن أحد كبار أصحاب المصلحة لديه نفوذ خفي يؤثر على المشروع رغم عدم ظهوره في قائمة المشاركين الرسميين. كيف تتعامل؟","opts":["تجاهله لأنه ليس رسمياً","تحديثه في قائمة أصحاب المصلحة، تقييم تأثيره، ووضع استراتيجية إشراك مناسبة","تجنبه تماماً","إخبار الراعي لمنع تدخله"],"ans":"B","exp":"تحديد أصحاب المصلحة عملية مستمرة. الإشراك المناسب لذوي التأثير الخفي يمنع المفاجآت ويستفيد من نفوذهم لصالح المشروع.","id":127},{"task":"Task 9: Collaborate with Stakeholders","q":"ما الأداة الأنسب لتصنيف أصحاب المصلحة بناءً على قوتهم واهتمامهم؟","opts":["WBS","Power/Interest Grid (مصفوفة القوة/الاهتمام)","Critical Path Method","Earned Value Analysis"],"ans":"B","exp":"مصفوفة القوة/الاهتمام أداة كلاسيكية لتصنيف أصحاب المصلحة وتحديد استراتيجية الإشراك (Manage Closely, Keep Satisfied, Keep Informed, Monitor).","id":128},{"task":"Task 9: Collaborate with Stakeholders","q":"في مشروع متعدد المنظمات، كيف يدير مدير المشروع التعاون بين فرق من شركات مختلفة؟","opts":["إجبار الجميع على اتباع ثقافة منظمته","وضع ميثاق مشترك، احترام ثقافات المنظمات، قنوات تواصل واضحة، وحوكمة متفق عليها","عزل كل فريق عن الآخر","تجنب أي تفاعل غير ضروري"],"ans":"B","exp":"التعاون عبر المنظمات يحتاج اتفاقاً صريحاً على المبادئ والقواعد، مع احترام للاختلافات الثقافية. الفرض يفشل.","id":129},{"task":"Task 9: Collaborate with Stakeholders","q":"صاحب مصلحة مقاوم للتغيير يعرقل تقدم المشروع باستمرار. ما أفضل نهج؟","opts":["تجاهله أو تجاوزه","فهم مخاوفه الحقيقية، إشراكه في الحلول، توفير المعلومات، وبناء فهم مشترك لقيمة التغيير","تصعيده فوراً للإدارة العليا","إخراجه من قائمة أصحاب المصلحة"],"ans":"B","exp":"المقاومة عادة تنبع من مخاوف مشروعة (فقدان السلطة، عدم الفهم، تأثيرات سلبية). فهمها ومعالجتها أفعل من المواجهة.","id":130},{"task":"Task 9: Collaborate with Stakeholders","q":"كيف يمكن \"تحسين المواءمة\" بين احتياجات أصحاب المصلحة وأهداف المشروع؟","opts":["إخفاء التضاربات عن الأطراف","حوار منتظم، توضيح المقايضات، تحديد أولويات بشكل تعاوني، وتحديثات شفافة عن التقدم","اتخاذ قرارات منفردة وفرضها","تأجيل المشاكل حتى نهاية المشروع"],"ans":"B","exp":"المواءمة عملية مستمرة لا حدث واحد. الحوار، المقايضات الواضحة، والشفافية تحافظ على التوافق طوال دورة حياة المشروع.","id":131},{"task":"Task 9: Collaborate with Stakeholders","q":"ما المقصود بـ \"Stakeholder Engagement Plan\" (خطة إشراك أصحاب المصلحة)؟","opts":["قائمة بأسماء أصحاب المصلحة فقط","وثيقة توضح استراتيجيات الإشراك لكل صاحب مصلحة، طرق التواصل، تكرار التحديثات، ومستوى المشاركة المطلوب","خطة إدارة الموارد","ميزانية المشروع"],"ans":"B","exp":"خطة الإشراك أداة محورية في PMI. تحول التحليل إلى إجراءات محددة لكل صاحب مصلحة.","id":132},{"task":"Task 9: Collaborate with Stakeholders","q":"ما أفضل وقت للبدء بتحديد أصحاب المصلحة في المشروع؟","opts":["بعد بدء التنفيذ","أثناء مرحلة بدء المشروع (Initiating) كجزء من Project Charter، مع تحديث مستمر طوال المشروع","في نهاية المشروع لإخبارهم بالنتائج","فقط عندما تظهر مشاكل"],"ans":"B","exp":"تحديد أصحاب المصلحة يبدأ مبكراً جداً (Project Charter) ويستمر طوال المشروع. الاكتشاف المبكر يمكّن من إشراك فعّال.","id":133},{"task":"Task 9: Collaborate with Stakeholders","q":"كيف يمكن قياس فعالية استراتيجية إشراك أصحاب المصلحة؟","opts":["بعدد الاجتماعات المنعقدة","بمؤشرات مثل مستوى الرضا، جودة التواصل، استجابة أصحاب المصلحة، وتقليل المفاجآت السلبية","بحجم البريد الإلكتروني المرسل","بعدد الحضور في الاجتماعات"],"ans":"B","exp":"قياس الفعالية يركز على النتائج (الرضا، الجودة، الاستجابة) لا على المخرجات الإجرائية (عدد الاجتماعات أو الإيميلات).","id":134},{"task":"Task 9: Collaborate with Stakeholders","q":"في فريق Agile، من المسؤول الأساسي عن إدارة العلاقة مع أصحاب المصلحة؟","opts":["Scrum Master فقط","Product Owner بشكل أساسي، مع دور تكميلي من Scrum Master وفريق التطوير","فريق التطوير وحده","المنظمة فقط"],"ans":"B","exp":"Product Owner هو الواجهة الأساسية لأصحاب المصلحة في Scrum: يجمع المتطلبات، يدير Backlog، ويوصل القيمة. Scrum Master يدعم تيسير التواصل.","id":135},{"task":"Task 9: Collaborate with Stakeholders","q":"تواجه ضغطاً من اثنين من أصحاب المصلحة بمطالب متعارضة. ما أفضل نهج؟","opts":["إرضاء الأقوى منهما","تيسير حوار بينهما لفهم الأولويات، التشاور مع الراعي عند الحاجة، والوصول إلى قرار مدعوم","اختيار جانب واحد وإهمال الآخر","تأجيل القرار"],"ans":"B","exp":"تيسير الحوار بين الأطراف يحول النزاع إلى تعاون. تصعيد للراعي عند الحاجة للحصول على حسم استراتيجي.","id":136},{"task":"Task 9: Collaborate with Stakeholders","q":"أي من الممارسات التالية تعزز التأثير الإيجابي على أصحاب المصلحة لتحقيق أهداف المشروع؟","opts":["التهديد بالعواقب","الإقناع المبني على البيانات والمصلحة المشتركة، بناء العلاقات، والمصداقية المستمرة","إخفاء الحقائق","التلاعب العاطفي"],"ans":"B","exp":"التأثير الأخلاقي يبنى على المصداقية، البيانات، وفهم مصالح الآخرين. التلاعب يدمر الثقة على المدى الطويل.","id":137},{"task":"Task 9: Collaborate with Stakeholders","q":"صاحب مصلحة مهم لم يحضر آخر 3 اجتماعات لمراجعة الحالة. ما أنسب تصرف؟","opts":["اعتباره غير مهتم وحذفه من القائمة","تواصل شخصي لفهم السبب، تقدير وقته، وتعديل آلية التواصل بما يناسبه","إرسال إشعار رسمي يطالب بحضوره","إلغاء الاجتماعات"],"ans":"B","exp":"الغياب قد يكون لأسباب متعددة (انشغال، تواصل غير مناسب، تراجع في الاهتمام). فهم السبب وتعديل النهج يحافظ على الإشراك.","id":138},{"task":"Task 10: Build Shared Understanding","q":"اكتشفت أن أعضاء الفريق يفهمون أحد المتطلبات الرئيسية بطرق مختلفة. ما الإجراء الأول؟","opts":["اختيار التفسير الذي يبدو منطقياً أكثر","تحليل سبب سوء الفهم، تيسير حوار مع جميع الأطراف، والتوصل إلى فهم مشترك موثق","تجاهل الاختلاف","إعادة كتابة المتطلب بكلمات مختلفة"],"ans":"B","exp":"بناء الفهم المشترك يبدأ بتحليل السبب (غموض في الصياغة، خلفيات مختلفة، إلخ). الحوار التيسيري يوصل إلى توافق موثق.","id":139},{"task":"Task 10: Build Shared Understanding","q":"خلال اجتماع تخطيط، أنت متأكد من وجود سوء فهم بين عضوين دون أن يصرحا بذلك. ماذا تفعل؟","opts":["الانتظار حتى يصرّحا بأنفسهما","التحقق بأسئلة موجهة (Active Listening, Restating)، توضيح المفاهيم، والتأكد من فهم مشترك","تجاهل الإشارات","افتراض أن المشكلة ستحل نفسها"],"ans":"B","exp":"التحقق الاستباقي عبر أسئلة موجهة وإعادة الصياغة يكشف سوء الفهم مبكراً. هذه مهارة جوهرية للقيادة.","id":140},{"task":"Task 10: Build Shared Understanding","q":"ما أفضل طريقة للتأكد من توافق الفريق على نتائج اجتماع مهم؟","opts":["افتراض أن الحضور يعني الفهم","تلخيص النقاط الرئيسية والقرارات في نهاية الاجتماع، توثيق ومشاركة محضر، وطلب التحقق من الحضور","إرسال محضر طويل دون متابعة","ترك كل عضو يأخذ ملاحظاته"],"ans":"B","exp":"التلخيص، التوثيق، والتحقق ممارسات لا غنى عنها لضمان الفهم المشترك. \"الحضور لا يعني الفهم\" قاعدة مهمة.","id":141},{"task":"Task 10: Build Shared Understanding","q":"ما المقصود بـ \"الوصول إلى الإجماع\" (Reaching Consensus) في إدارة المشاريع؟","opts":["حصول الجميع على ما يريدون بالضبط","اتفاق يمكن لجميع الأطراف دعمه ولو لم يكن خيارهم الأول، بعد سماع كل الأصوات","تصويت الأغلبية","قرار يفرضه القائد بعد سماع الجميع"],"ans":"B","exp":"الإجماع ليس إجماعاً مطلقاً ولا تصويتاً. هو حل يقبل به الجميع ويلتزمون به، حتى لو لم يكن خيارهم الأول.","id":142},{"task":"Task 10: Build Shared Understanding","q":"أي تقنية تستخدم بشكل خاص للتحقق من السبب الجذري لسوء الفهم؟","opts":["Pareto Analysis","5 Whys","Monte Carlo Simulation","PERT Estimation"],"ans":"B","exp":"تقنية 5 Whys تستخدم في تحليل السبب الجذري. السؤال المتكرر \"لماذا؟\" يكشف الأسباب العميقة وراء الأعراض.","id":143},{"task":"Task 10: Build Shared Understanding","q":"في فريق متعدد التخصصات، يستخدم المهندسون مصطلحات تقنية لا يفهمها أصحاب المصلحة من قسم التسويق. كيف تعالج هذا؟","opts":["إجبار التسويق على تعلم المصطلحات التقنية","تيسير ترجمة المصطلحات، تطوير مسرد مشترك، وتشجيع التواصل بلغة بسيطة مع الأطراف غير التقنية","فصل التواصل بين القسمين","تجاهل الفجوة"],"ans":"B","exp":"اللغة المشتركة جسر للفهم. تسهيل الترجمة وبناء مسرد يحول الفجوات اللغوية إلى تواصل فعال.","id":144},{"task":"Task 10: Build Shared Understanding","q":"اكتشفت أن صاحب مصلحة فهم نتيجة المشروع بشكل مختلف عن الفريق بعد التسليم. ما الإجراء؟","opts":["اعتبار المشروع منتهياً ولا تتدخل","تحليل أين حدث سوء التفاهم في رحلة المشروع، تيسير حوار للوصول إلى توافق، وتوثيق الدروس","إلقاء اللوم على صاحب المصلحة لعدم وضوحه","إعادة المشروع من الصفر"],"ans":"B","exp":"تحليل سوء التفاهم بعد التسليم درس قيم للمشاريع المستقبلية. الحوار قد يحل المشكلة الحالية، والتوثيق يمنع تكرارها.","id":145},{"task":"Task 10: Build Shared Understanding","q":"ما دور \"الاستماع الفعّال\" (Active Listening) في بناء الفهم المشترك؟","opts":["إظهار الاهتمام فقط","فهم عميق لكلام المتحدث، التحقق بإعادة الصياغة، وطرح أسئلة استيضاحية لضمان الفهم الصحيح","إيقاف المتحدث للرد","حفظ كل كلمة بحرفيتها"],"ans":"B","exp":"الاستماع الفعّال مهارة محورية: ليس مجرد سماع، بل فهم وتأكيد عبر إعادة الصياغة والأسئلة، مما يبني فهماً مشتركاً حقيقياً.","id":146},{"task":"Task 10: Build Shared Understanding","q":"أثناء جلسة Sprint Planning، يبدو أن الفريق وصاحب المنتج يفسرون قصة المستخدم (User Story) بطرق مختلفة. ما الإجراء؟","opts":["البدء بالتطوير ومعالجة الفروقات لاحقاً","إعادة كتابة قصة المستخدم مع معايير قبول واضحة بالتعاون بين الفريق وصاحب المنتج","اتخاذ قرار من Scrum Master وفرضه","تأجيل القصة لسبرنت لاحق"],"ans":"B","exp":"معايير القبول الواضحة (Acceptance Criteria) أداة محورية لبناء فهم مشترك. كتابتها تعاونياً يحول الغموض إلى وضوح.","id":147},{"task":"Task 10: Build Shared Understanding","q":"بعد التوصل إلى اتفاق في اجتماع، أي ممارسة تدعم استمرار الالتزام بالنتيجة؟","opts":["الاكتفاء بمحضر الاجتماع","توثيق القرار، تكليف مسؤول لكل بند، تحديد موعد متابعة، ومراجعة في الاجتماعات اللاحقة","تجاهل الموضوع بعد الاجتماع","إعلانه على الملأ فوراً"],"ans":"B","exp":"تحويل القرارات إلى أفعال محددة بمسؤول ومتابعة يضمن التنفيذ. القرارات بدون متابعة تتلاشى بسرعة.","id":148},{"task":"Task 10: Build Shared Understanding","q":"في فريق دولي، قد تختلف فهم الأطراف للالتزامات بسبب اختلافات ثقافية في التواصل. كيف تتعامل؟","opts":["افتراض أن \"نعم\" تعني \"نعم\" دائماً","بناء وعي ثقافي، التأكد من التزامات صريحة (Yes, but specifically...)، توثيق الاتفاقات، والتحقق المتكرر","تجنب التعاون عبر الثقافات","فرض ثقافة واحدة على الجميع"],"ans":"B","exp":"الذكاء الثقافي في التواصل يدرك أن نفس الكلمات قد تعني أشياء مختلفة. التحقق الصريح والتوثيق يبني فهماً موضوعياً.","id":149},{"task":"Task 10: Build Shared Understanding","q":"في حالة عدم وضوح وثائق المشروع لأعضاء جدد في الفريق، ما الإجراء الأنسب؟","opts":["تركهم يفسرون الوثائق بأنفسهم","جلسات تأهيل (Onboarding) مع شرح السياق، إقران بأعضاء خبراء، وتشجيع أسئلة بدون حرج","إعطاؤهم وقتاً طويلاً للتعلم منفردين","إعادة المشروع من الصفر"],"ans":"B","exp":"تأهيل فعّال يبني فهماً مشتركاً سريعاً. شرح السياق، الإقران، وفتح قنوات الأسئلة يقصّر منحنى التعلم.","id":150},{"task":"Task 11: Engage and Support Virtual Teams","q":"ما التحدي الأكثر شيوعاً في إدارة الفرق الافتراضية؟","opts":["ارتفاع التكاليف","صعوبة بناء الثقة والتواصل الفعّال، وفقدان الإشارات غير اللفظية، واختلافات المناطق الزمنية والثقافية","نقص الأدوات التقنية","زيادة الإنتاجية المفرطة"],"ans":"B","exp":"تحديات الفرق الافتراضية تتعلق بالعنصر الإنساني أكثر من التقني: الثقة، التواصل، التوقيت، والثقافة هي الجوانب الحرجة.","id":151},{"task":"Task 11: Engage and Support Virtual Teams","q":"ما أفضل ممارسة لإدارة فريق افتراضي عبر مناطق زمنية متعددة؟","opts":["إجبار الجميع على العمل بتوقيت موحد","تنويع توقيتات الاجتماعات لتوزيع العبء، استخدام التواصل غير المتزامن، وتوثيق دقيق للقرارات","تقليل الاجتماعات إلى الحد الأدنى","تجاهل اختلافات المناطق الزمنية"],"ans":"B","exp":"العدالة في تحمل عبء التوقيت، والاستفادة من التواصل غير المتزامن (Documentation, Async Updates) هي مفتاح الفرق العالمية.","id":152},{"task":"Task 11: Engage and Support Virtual Teams","q":"كيف يمكن بناء الثقة في فريق افتراضي؟","opts":["تجنب أي تفاعل غير رسمي","اجتماعات افتراضية بكاميرا، أوقات للتفاعل غير الرسمي، شفافية في القرارات، والوفاء بالالتزامات","زيادة الرقابة على ساعات العمل","تجنب مناقشة الموضوعات الشخصية"],"ans":"B","exp":"الثقة في الفرق الافتراضية تحتاج جهداً مقصوداً: الكاميرا، التفاعل غير الرسمي، والشفافية تعوض غياب التواجد الجسدي.","id":153},{"task":"Task 11: Engage and Support Virtual Teams","q":"أحد أعضاء الفريق الافتراضي يبدو منعزلاً ومتراجعاً في المشاركة. ما أنسب تصرف؟","opts":["تجاهل الموضوع","تواصل فردي خاص لفهم الحالة، التحقق من توفر الدعم اللازم، وتشجيع المشاركة بطرق مناسبة","إخراجه من الفريق","إجباره على المشاركة في كل اجتماع"],"ans":"B","exp":"في الفرق الافتراضية، علامات الانعزال قد تخفى. التواصل الفردي الاستباقي يكشف المشاكل ويقدم الدعم قبل تفاقمها.","id":154},{"task":"Task 11: Engage and Support Virtual Teams","q":"ما أهمية اختيار أدوات التعاون المناسبة لفريق افتراضي؟","opts":["غير مهم، أي أداة تكفي","أساسي، فاختيار الأدوات يؤثر على فاعلية التواصل، الإنتاجية، وتجربة العمل اليومي","مهم فقط للفرق التقنية","الأداة الأغلى دائماً الأفضل"],"ans":"B","exp":"أدوات التعاون (تواصل، إدارة مهام، توثيق، اجتماعات) تحدد تجربة الفريق الافتراضي. الاختيار المدروس يعزز الكفاءة بشكل كبير.","id":155},{"task":"Task 11: Engage and Support Virtual Teams","q":"كيف يمكن لمدير المشروع تقييم فعالية إشراك الفريق الافتراضي بشكل مستمر؟","opts":["افتراض الفعالية ما لم تظهر مشاكل","استطلاعات دورية، اجتماعات 1-on-1، مؤشرات أداء، وتغذية راجعة منتظمة من الفريق","قياس عدد ساعات الاجتماعات","الاعتماد على إحصاءات الإيميل"],"ans":"B","exp":"تقييم فعالية الإشراك يحتاج آليات متعددة: قياس مباشر (استطلاعات) وحوار حقيقي (1-on-1) لكشف القضايا الخفية.","id":156},{"task":"Task 11: Engage and Support Virtual Teams","q":"في فريق افتراضي يجمع ثقافات متنوعة، أي ممارسة تساعد على بناء التماسك؟","opts":["تجاهل الاختلافات الثقافية تماماً","بناء وعي ثقافي، إنشاء قواعد تواصل محترمة، الاحتفاء بالأعياد المختلفة، وأنشطة بناء فريق افتراضية شاملة","اختيار أعضاء من ثقافة واحدة فقط","فرض ثقافة موحدة"],"ans":"B","exp":"إدارة التنوع في الفرق الافتراضية تتطلب جهداً مقصوداً للوعي والاحتفاء، مما يبني انتماءً وقوة تنوع.","id":157},{"task":"Task 11: Engage and Support Virtual Teams","q":"ما الفرق الأساسي بين التواصل المتزامن وغير المتزامن في فرق العمل الافتراضية؟","opts":["لا فرق بينهما","المتزامن يحدث في الوقت الفعلي (اجتماعات، محادثات حية)، غير المتزامن يسمح بالاستجابة في أوقات مختلفة (بريد، توثيق)","المتزامن أفضل دائماً","غير المتزامن مخصص للأعمال البسيطة فقط"],"ans":"B","exp":"كل نوع له استخداماته. الفرق الفعّالة عن بُعد تستخدم المتزامن للحوار والقرارات المعقدة، وغير المتزامن للتحديثات والعمل العميق.","id":158},{"task":"Task 11: Engage and Support Virtual Teams","q":"تبدأ مشروعاً جديداً بفريق افتراضي. ما الإجراء الأكثر أولوية في الأسبوع الأول؟","opts":["البدء بالتطوير مباشرة","اجتماع إطلاق افتراضي، إنشاء عقد فريق، اتفاق على الأدوات وقواعد التواصل، وأنشطة تعارف","إرسال خطة المشروع بالبريد فقط","تأجيل التواصل حتى تظهر مشاكل"],"ans":"B","exp":"بداية قوية للفريق الافتراضي تبني الأساس للنجاح. الاستثمار في التأسيس يوفر أضعافاً من المشاكل لاحقاً.","id":159},{"task":"Task 11: Engage and Support Virtual Teams","q":"أحد أعضاء الفريق يطلب التواجد في الموقع دورياً (Co-location دورياً). كيف تتعامل مع طلبه في فريق افتراضي؟","opts":["رفض الطلب لأن الفريق افتراضي","تقييم القيمة (بناء علاقات، حل قضايا معقدة)، الموازنة مع التكلفة، وتجربة لقاءات دورية إذا أمكن","إجبار الجميع على التواجد في الموقع","تجاهل الطلب"],"ans":"B","exp":"اللقاءات الدورية في الموقع (Periodic Co-location) ممارسة موصى بها لكثير من الفرق الافتراضية. تبني علاقات وتحل قضايا يصعب حلها افتراضياً.","id":160},{"task":"Task 11: Engage and Support Virtual Teams","q":"كيف يمكن لـ Daily Standup أن يكون فعالاً في فريق Agile افتراضي؟","opts":["تجنبه تماماً لأنه غير عملي","اجتماع قصير محدد (15 دقيقة)، فيديو مفعّل، تركيز على التزامن وكشف العوائق، وتوثيق العوائق للمتابعة","اجتماع يومي طويل لمناقشة كل شيء","إلغاء كل الاجتماعات"],"ans":"B","exp":"Daily Standup الفعّال في الفرق الافتراضية يحافظ على الانضباط الزمني، يستخدم الفيديو، ويوثق العوائق بدقة للمتابعة بين الاجتماعات.","id":161},{"task":"Task 11: Engage and Support Virtual Teams","q":"اكتشفت أن أحد أعضاء الفريق الافتراضي يعاني من ضعف اتصال إنترنت. ما أنسب تصرف؟","opts":["اللوم على الموظف لعدم وجود اتصال جيد","تقييم خيارات الدعم: ميزانية لتحسين الاتصال، آليات تواصل غير متزامنة، وإعداد بدائل عند الفشل","إخراجه من الفريق","تجاهل المشكلة"],"ans":"B","exp":"البنية التحتية مسؤولية مشتركة في العمل عن بُعد. توفير الدعم اللازم استثمار في إنتاجية الفريق.","id":162},{"task":"Task 11: Engage and Support Virtual Teams","q":"ما أفضل ممارسة لتوثيق القرارات في فريق افتراضي؟","opts":["الاعتماد على ذاكرة الأعضاء","نظام توثيق مركزي ومتاح، تحديث فوري بعد القرارات، تتبع تاريخ التغييرات، وقابلية البحث","إرسال إيميلات منفصلة لكل قرار","ترك كل عضو يحتفظ بسجله"],"ans":"B","exp":"في الفرق الافتراضية، التوثيق المركزي القابل للبحث هو \"الذاكرة الجماعية\". غيابه يخلق فوضى وفقدان للمعلومات.","id":163},{"task":"Task 11: Engage and Support Virtual Teams","q":"أي من المؤشرات التالية تشير إلى مشاكل محتملة في فريق افتراضي؟","opts":["كثرة الاجتماعات الناجحة","انخفاض المشاركة في الاجتماعات، تأخر الاستجابة، صمت الأعضاء في القنوات الجماعية، وتراجع جودة المخرجات","وجود خطة مشروع موثقة","استخدام أدوات تعاون متعددة"],"ans":"B","exp":"علامات تراجع الإشراك في الفرق الافتراضية قد تكون خفية. الاستجابة لها مبكراً تمنع تفاقم الانعزال وتراجع الأداء.","id":164},{"task":"Task 12: Define Team Ground Rules","q":"ما الغرض الأساسي من \"قواعد عمل الفريق\" (Team Ground Rules)؟","opts":["تقييد حرية أعضاء الفريق","تحديد توقعات السلوك، التواصل، وحل النزاع، وبناء بيئة عمل منتجة ومحترمة","تعقيد العمل اليومي","تجنب اتخاذ القرارات الصعبة"],"ans":"B","exp":"قواعد العمل تخلق بيئة عمل واضحة ومحترمة، تقلل النزاعات، وتعزز الإنتاجية. هي عقد سلوكي تعاوني، لا قيود فوقية.","id":165},{"task":"Task 12: Define Team Ground Rules","q":"كيف يجب أن تُوضع قواعد عمل الفريق لضمان قبولها والتزام الأعضاء بها؟","opts":["يضعها مدير المشروع منفرداً ويفرضها","يطورها الفريق بشكل تعاوني، تُوثَّق في عقد الفريق، وتُراجَع دورياً","تنسخ من مشروع سابق دون مراجعة","تترك ضمنية دون كتابة"],"ans":"B","exp":"الملكية المشتركة لقواعد العمل تعزز الالتزام الحقيقي بها. القواعد المفروضة من أعلى تُتبع بالحد الأدنى.","id":166},{"task":"Task 12: Define Team Ground Rules","q":"أي من الموضوعات التالية يجب أن تشمله قواعد عمل الفريق؟","opts":["ساعات العمل فقط","بروتوكولات التواصل، اتخاذ القرار، حل النزاع، تقديم العمل، احترام الأوقات، وآداب الاجتماعات","الراتب فقط","اللوائح القانونية فقط"],"ans":"B","exp":"قواعد عمل الفريق الشاملة تغطي السلوك اليومي بشكل واسع. كلما زادت التغطية، قلت المساحة لسوء الفهم والنزاع.","id":167},{"task":"Task 12: Define Team Ground Rules","q":"أحد أعضاء الفريق ينتهك قاعدة عمل متفق عليها بشكل متكرر. ما أنسب تصرف؟","opts":["تجاهل الأمر لتجنب المواجهة","محادثة خاصة لفهم السبب، تذكير بالقاعدة وأثرها على الفريق، ومتابعة الالتزام مع تدرج في الإجراء","العقوبة الفورية بدون نقاش","تغيير القاعدة لتناسبه"],"ans":"B","exp":"الانتهاك المتكرر يحتاج معالجة منهجية. الحوار أولاً (لفهم السبب)، ثم تدرج في الإجراءات يحافظ على القاعدة دون تدمير العلاقة.","id":168},{"task":"Task 12: Define Team Ground Rules","q":"كيف ترسخ قواعد عمل الفريق في الممارسة اليومية؟","opts":["وضعها على لوحة الإعلانات فقط","النمذجة بالقدوة، الإشارة إليها في الاجتماعات، الاعتراف بالالتزام، ومراجعتها دورياً","إرسالها بالبريد مرة واحدة","تركها دون تذكير"],"ans":"B","exp":"القواعد تترسخ بالممارسة لا بالكتابة. النمذجة، التذكير، الاعتراف، والمراجعة الدورية تحول الكلمات إلى ثقافة.","id":169},{"task":"Task 12: Define Team Ground Rules","q":"ما العلاقة بين قواعد عمل الفريق والمبادئ التنظيمية للشركة؟","opts":["لا علاقة بينهما","قواعد الفريق يجب أن تتسق مع المبادئ التنظيمية، وتخصصها للسياق المحدد للمشروع","قواعد الفريق تحل محل المبادئ التنظيمية","المبادئ التنظيمية تلغي قواعد الفريق"],"ans":"B","exp":"قواعد الفريق تخصص المبادئ التنظيمية لسياق المشروع، دون أن تتعارض معها. تحقق التوافق المرن مع الثقافة المؤسسية.","id":170},{"task":"Task 12: Define Team Ground Rules","q":"في فريق يتضمن أعضاءً من ثقافات مختلفة، كيف تضع قواعد عمل تحترم التنوع؟","opts":["فرض ثقافة واحدة","حوار مفتوح حول التوقعات الثقافية، اتفاق على قواعد محترمة للجميع، ومرونة في التطبيق","تجاهل الاختلافات الثقافية","وضع قواعد منفصلة لكل ثقافة"],"ans":"B","exp":"قواعد الفريق المتنوع تبنى على فهم متبادل واحترام للاختلافات. الحوار المفتوح يكشف الافتراضات الثقافية ويبني توافقاً حقيقياً.","id":171},{"task":"Task 12: Define Team Ground Rules","q":"متى يجب مراجعة قواعد عمل الفريق وتحديثها؟","opts":["أبداً بعد وضعها","دورياً (مثلاً في كل Retrospective)، وعند التغييرات الكبيرة في الفريق أو ظهور مشاكل متكررة","في نهاية المشروع فقط","كل يوم"],"ans":"B","exp":"القواعد ليست مقدسة. مراجعتها دورياً تضمن صلاحيتها مع تطور الفريق والظروف. Retrospective فرصة طبيعية لهذه المراجعة.","id":172},{"task":"Task 12: Define Team Ground Rules","q":"أي من القواعد التالية تعد مثالاً جيداً على قاعدة عمل فريق فعالة؟","opts":["نتعاون أحياناً","نبدأ الاجتماعات في الوقت المحدد، نُبلغ مسبقاً عن أي تأخير، ونحترم وقت الجميع","كن لطيفاً","اعمل أكثر"],"ans":"B","exp":"القواعد الفعالة محددة وقابلة للقياس وموجهة بسلوك واضح. القواعد المبهمة (\"كن لطيفاً\") لا توجّه السلوك فعلياً.","id":173},{"task":"Task 12: Define Team Ground Rules","q":"كيف يتم التعامل مع تعارض بين قاعدة من قواعد الفريق ومتطلب من صاحب مصلحة خارجي؟","opts":["تجاهل قواعد الفريق","تحليل التعارض، التشاور مع الفريق، التواصل مع صاحب المصلحة لشرح السبب، والوصول إلى حل متفق عليه","إلغاء كل قواعد الفريق","تجاهل صاحب المصلحة"],"ans":"B","exp":"التعارضات تحدث وتحل بالحوار. شرح أسباب القواعد لأصحاب المصلحة يبني الفهم. قد تحتاج القاعدة للتعديل أو يحتاج المتطلب للمراجعة.","id":174},{"task":"Task 12: Define Team Ground Rules","q":"في بداية المشروع، أحد الأعضاء يعترض على إحدى قواعد العمل المقترحة. كيف تتعامل؟","opts":["تجاهل اعتراضه","الاستماع إلى مخاوفه، تيسير حوار مع الفريق، تعديل القاعدة إذا كانت المخاوف مشروعة، أو شرح الأسباب","فرض القاعدة بالقوة","إخراجه من الفريق"],"ans":"B","exp":"الاعتراضات في مرحلة وضع القواعد فرصة لبناء قواعد أفضل وأكثر قبولاً. تيسير الحوار جوهر بناء فريق.","id":175},{"task":"Task 12: Define Team Ground Rules","q":"ما التأثير المباشر لغياب قواعد عمل واضحة في فريق المشروع؟","opts":["زيادة الإبداع","غموض في التوقعات، نزاعات أكثر، إنتاجية أقل، وصعوبة في حل المشاكل السلوكية","تحسن الإنتاجية","لا تأثير"],"ans":"B","exp":"غياب القواعد لا يعني حرية بل غموضاً. هذا الغموض يولّد نزاعات وعدم كفاءة. القواعد الواضحة تطلق الإبداع ضمن إطار آمن.","id":176},{"task":"Task 13: Mentor Relevant Stakeholders","q":"أي من العبارات التالية يصف بدقة دور الموجه (Mentor)؟","opts":["شخص يوجه الأوامر","شخص ذو خبرة يقدم إرشاداً، حكمة، وتغذية راجعة بنّاءة لدعم تطور شخص آخر طويل الأمد","مدرب فني يحل المشاكل التقنية","مدير مباشر"],"ans":"B","exp":"التوجيه (Mentoring) علاقة قائمة على المشاركة الطوعية لتطوير الموجَّه. يركز على النمو الشامل لا على المهام التقنية.","id":177},{"task":"Task 13: Mentor Relevant Stakeholders","q":"كيف يمكن لمدير المشروع تخصيص وقت للتوجيه في جدوله المزدحم؟","opts":["ترك التوجيه فقط للظروف غير المخططة","تخصيص وقت منتظم في الجدول (1-on-1)، تحديد أولوية للتوجيه كاستثمار في الفريق","إلغاء التوجيه عند ضيق الوقت","تفويض التوجيه بالكامل لطرف آخر"],"ans":"B","exp":"التوجيه استثمار استراتيجي في الفريق وأصحاب المصلحة. تخصيص وقت رسمي يضمن استمراريته رغم الضغوط.","id":178},{"task":"Task 13: Mentor Relevant Stakeholders","q":"أحد أعضاء الفريق الجدد يطلب توجيهاً لتطوير مساره المهني. ما أنسب تصرف؟","opts":["رفض الطلب لأن المسار خارج نطاق المشروع","قبول الدور أو ترشيح موجه آخر مناسب، وضع توقعات واضحة، وتخصيص وقت منتظم","تجاهل الطلب","إحالته إلى الموارد البشرية فقط"],"ans":"B","exp":"دعم تطور الأفراد دور قيادي مهم. القائد الخادم يستثمر في فريقه، حتى لو ذلك خارج النطاق التقني المباشر للمشروع.","id":179},{"task":"Task 13: Mentor Relevant Stakeholders","q":"ما الفرق الأساسي بين Coaching و Mentoring؟","opts":["هما مترادفان","Coaching تكتيكي مركز على أداء محدد، بينما Mentoring استراتيجي شامل ومرتبط بتطور المسار المهني","Coaching للموظفين الجدد فقط","Mentoring يكون مدفوع الأجر دائماً"],"ans":"B","exp":"Coaching يستهدف تحسين أداء/مهارة محددة في وقت محدد. Mentoring علاقة طويلة الأمد تركز على النمو الشامل والتطور المهني.","id":180},{"task":"Task 13: Mentor Relevant Stakeholders","q":"كيف يمكن التعرف على فرص التوجيه في بيئة المشروع؟","opts":["انتظار طلب صريح من الموجَّه","مراقبة احتياجات النمو، التحديات المتكررة، الأسئلة المتكررة، وفجوات المهارات، والمبادرة بتقديم التوجيه","تجاهل العلامات الخفية","افتراض عدم الحاجة للتوجيه"],"ans":"B","exp":"فرص التوجيه غالباً ضمنية. القائد المتيقظ يلاحظها ويستجيب لها قبل أن تتحول إلى مشاكل أداء.","id":181},{"task":"Task 13: Mentor Relevant Stakeholders","q":"في علاقة توجيه، أي ممارسة أكثر فاعلية؟","opts":["إخبار الموجَّه بكل الإجابات","طرح أسئلة قوية تساعد الموجَّه على التفكير العميق، الاستماع، ومشاركة الخبرة بشكل سياقي","حل مشاكل الموجَّه بدلاً منه","إعطاء أوامر صارمة"],"ans":"B","exp":"التوجيه الفعال يطور تفكير الموجَّه، لا يستبدله. الأسئلة القوية والاستماع يبنيان قدرات مستدامة.","id":182},{"task":"Task 13: Mentor Relevant Stakeholders","q":"تواجه مديراً متوسطاً يطلب توجيهك في إدارة مشروع كبير. كيف تتعامل؟","opts":["رفض الطلب لتجنب أي تعارض","تقدير الفرصة، الموافقة بشرط الوضوح في الحدود، وتقديم توجيه يحترم خبرته ويوجه نموه","إعطاء أوامر تنفيذية","إحالته فقط للقراءة الذاتية"],"ans":"B","exp":"التوجيه يصلح لمختلف المستويات. الحدود الواضحة (نطاق، تواتر، حدود السرية) تحمي العلاقة وتعظم الفائدة.","id":183},{"task":"Task 13: Mentor Relevant Stakeholders","q":"أحد أصحاب المصلحة (Sponsor جديد) لديه فجوة في فهم منهجية Agile. كيف يمكنك مساعدته كموجه غير رسمي؟","opts":["تجنب الموضوع","تقديم سياق ومعلومات بطريقة احترامية، مشاركة موارد قراءة، وعقد جلسات نقاش، وربط النظرية بالواقع","انتظار أن يحضر دورة رسمية","إخباره بأنه يجب أن يعرف"],"ans":"B","exp":"التوجيه المتبادل (حتى للمستويات الأعلى) يخدم المشروع. تقديم المساعدة بأسلوب محترم يبني العلاقة ويحسن نتائج المشروع.","id":184},{"task":"Task 13: Mentor Relevant Stakeholders","q":"كيف يمكن قياس فعالية التوجيه؟","opts":["بعدد ساعات الجلسات","بتقدم الموجَّه نحو أهدافه، تحسن مهاراته، نمو ثقته بنفسه، وتطبيق المعرفة في العمل الفعلي","بعدد التغذية الراجعة المرسلة","بالنية الحسنة فقط"],"ans":"B","exp":"نتائج التوجيه تقاس بالأثر على الموجَّه، لا بالمدخلات. التغيير السلوكي والنمو الحقيقي هما المعيار.","id":185},{"task":"Task 13: Mentor Relevant Stakeholders","q":"ما أهمية بناء ثقافة توجيه في المنظمة بشكل عام؟","opts":["غير مهم","تنشر المعرفة، تطور القادة المستقبليين، تحسن الاحتفاظ بالمواهب، وتعزز الأداء التنظيمي طويل الأمد","تكلفتها أكبر من فائدتها","تبطئ العمل"],"ans":"B","exp":"ثقافة التوجيه استثمار مؤسسي عميق. تبني قيادة المستقبل وتنشر المعرفة بطريقة طبيعية ومستدامة.","id":186},{"task":"Task 14: Emotional Intelligence","q":"ما المقصود بـ \"الذكاء العاطفي\" في سياق إدارة المشاريع؟","opts":["القدرة على التحكم بمشاعر الفريق وفرضها","القدرة على إدراك وفهم وإدارة المشاعر الذاتية والمشاعر الآخرين لبناء علاقات فعّالة","إخفاء كل المشاعر في العمل","التركيز على الجانب الفني فقط"],"ans":"B","exp":"الذكاء العاطفي (EI/EQ) يجمع الوعي الذاتي، الإدارة الذاتية، الوعي الاجتماعي، وإدارة العلاقات. مهارة محورية للقادة الفعالين.","id":187},{"task":"Task 14: Emotional Intelligence","q":"ما المكونات الأربعة الرئيسية للذكاء العاطفي وفقاً لـ Daniel Goleman؟","opts":["الذكاء، المعرفة، المهارة، الخبرة","الوعي الذاتي، الإدارة الذاتية، الوعي الاجتماعي، إدارة العلاقات","السرعة، الدقة، الكفاءة، الإنتاجية","التخطيط، التنفيذ، المراقبة، الإغلاق"],"ans":"B","exp":"نموذج Goleman للذكاء العاطفي يتضمن: 1) الوعي الذاتي، 2) الإدارة الذاتية، 3) الوعي الاجتماعي (التعاطف)، 4) إدارة العلاقات.","id":188},{"task":"Task 14: Emotional Intelligence","q":"في اجتماع متوتر، تشعر بالغضب من تعليق غير مبرر من صاحب مصلحة. ما أفضل تصرف وفقاً للذكاء العاطفي؟","opts":["الرد فوراً بنفس الحدة","التعرف على المشاعر، أخذ نفس عميق، الاستجابة بهدوء وحرفية، ومعالجة الموضوع لاحقاً إذا لزم","الانسحاب من الاجتماع","إخفاء المشاعر تماماً"],"ans":"B","exp":"الوعي الذاتي والإدارة الذاتية في الفعل. التعرف على المشاعر لا يعني التحرك بها، بل القدرة على اختيار الاستجابة المناسبة.","id":189},{"task":"Task 14: Emotional Intelligence","q":"كيف يمكن قياس الذكاء العاطفي لأعضاء الفريق؟","opts":["بمؤشرات الأداء التقنية فقط","أدوات مثل MBTI, DISC, EQ-i, ومؤشرات سلوكية في الموقف","الاعتماد على الحدس فقط","بدرجات اختبار الذكاء التقليدي"],"ans":"B","exp":"أدوات مؤشرات الشخصية والذكاء العاطفي (MBTI, DISC, EQ-i) أدوات منظمة لفهم السلوك وتطوير الفهم الذاتي والجماعي.","id":190},{"task":"Task 14: Emotional Intelligence","q":"لاحظت أن أحد كبار أصحاب المصلحة يبدو متوتراً جداً قبل الاجتماع. كيف يساعد الذكاء العاطفي هنا؟","opts":["تجاهل التوتر والمضي قدماً","إظهار التعاطف، التعرف على التوتر، وتعديل أسلوبك ووتيرتك لاستيعاب حالته العاطفية","إخباره بأن يهدأ","تأجيل الاجتماع لأجل غير مسمى"],"ans":"B","exp":"الوعي الاجتماعي (التعاطف) يقرأ الحالة العاطفية للآخرين، وإدارة العلاقات تعدل النهج وفقاً لها، مما يحسن جودة التفاعل.","id":191},{"task":"Task 14: Emotional Intelligence","q":"ما العلاقة بين الذكاء العاطفي وأداء الفريق؟","opts":["لا علاقة بينهما","الذكاء العاطفي العالي للقائد يعزز ثقة الفريق، يحسن التواصل، يقلل النزاعات، ويرفع الأداء","الذكاء العاطفي يبطئ العمل","الذكاء العاطفي ضروري فقط في مشاريع الموارد البشرية"],"ans":"B","exp":"أبحاث Goleman وآخرين تظهر ارتباطاً قوياً بين الذكاء العاطفي للقادة وأداء الفرق. الجانب الإنساني محرك أساسي للنتائج.","id":192},{"task":"Task 14: Emotional Intelligence","q":"في فريق متنوع، يتفاعل عضوان بأساليب مختلفة جداً (واحد منفتح والآخر متحفظ). كيف تتعامل؟","opts":["إجبار المتحفظ على أن يكون منفتحاً","تقدير أن الاختلافات في الشخصيات طبيعية، تكييف نهج التواصل مع كل واحد، وخلق بيئة آمنة للجميع","تفضيل المنفتح في الاجتماعات","فصل الأعضاء"],"ans":"B","exp":"احترام الاختلافات الشخصية وتكييف التواصل معها يطلق إمكانات الجميع. مؤشرات الشخصية تساعد في فهم هذه الاختلافات.","id":193},{"task":"Task 14: Emotional Intelligence","q":"أي من مهارات الذكاء العاطفي تتعلق بفهم مشاعر الآخرين دون الانجراف بها؟","opts":["الإدارة الذاتية","التعاطف (Empathy)","التحفيز الذاتي","إدارة العلاقات"],"ans":"B","exp":"التعاطف (Empathy) جزء من الوعي الاجتماعي: فهم مشاعر الآخرين دون الذوبان فيها. مهارة محورية للقائد الفعال.","id":194},{"task":"Task 14: Emotional Intelligence","q":"كيف يمكن لمدير المشروع تطوير ذكائه العاطفي الذاتي؟","opts":["افتراض أنه عاطفي بطبيعته","ممارسة التأمل، طلب تغذية راجعة 360 درجة، استخدام أدوات تقييم الشخصية، والتدريب على الوعي الذاتي","تجنب التفكير في المشاعر","الاعتماد على رد فعل تلقائي"],"ans":"B","exp":"الذكاء العاطفي مهارة قابلة للتطوير عبر الممارسة المستمرة. التغذية الراجعة المتعددة المصادر وأدوات التقييم توفر بيانات للنمو.","id":195},{"task":"Task 14: Emotional Intelligence","q":"أحد أعضاء الفريق يأتي بمشاعر شخصية صعبة إلى العمل. ما أنسب تصرف؟","opts":["تجاهل المشاعر تماماً","إظهار التعاطف بحدود مهنية، تقديم دعم متاح (مرونة، إحالة لبرامج المساعدة)، والحفاظ على كرامته","إخراجه من الفريق","مشاركة الفريق بقصته"],"ans":"B","exp":"التعاطف المهني يدرك إنسانية الزميل دون تخطي الحدود. تقديم الدعم المناسب يقوي العلاقة ويحافظ على الكرامة.","id":196},{"task":"Task 14: Emotional Intelligence","q":"ما دور الذكاء العاطفي في حل النزاعات بين أعضاء الفريق؟","opts":["لا دور له","يساعد على فهم المشاعر الكامنة، تخفيف التوتر، اكتشاف المصالح الحقيقية، وتيسير حلول مرضية","يعقّد الموضوع","ضروري فقط في النزاعات الكبيرة"],"ans":"B","exp":"كثير من النزاعات جذورها عاطفية لا منطقية. الذكاء العاطفي يكشف الأبعاد الإنسانية وييسر حلولاً مستدامة.","id":197},{"task":"Task 14: Emotional Intelligence","q":"خلال أزمة في المشروع، الفريق متوتر ومحبط. كيف تستخدم الذكاء العاطفي كقائد؟","opts":["الضغط أكثر على الفريق","الاعتراف بمشاعرهم، إظهار الهدوء والثقة، تقديم رؤية واضحة للمضي قدماً، وتحفيز الفريق بصدق","تجاهل مشاعرهم","إلقاء اللوم على الفريق"],"ans":"B","exp":"في الأزمات، القيادة العاطفية تقوي الفريق. الاعتراف بالمشاعر يبني الثقة، والرؤية الواضحة تستعيد الزخم.","id":198},{"task":"Task 14: Emotional Intelligence","q":"أي من السلوكيات التالية تشير إلى ضعف الذكاء العاطفي لدى القائد؟","opts":["الاستماع الفعال","التحكم في ردود الفعل تحت الضغط","الانفعالات غير المنضبطة، عدم الإصغاء، وعدم إدراك أثر سلوكه على الآخرين","طلب التغذية الراجعة"],"ans":"C","exp":"ضعف الذكاء العاطفي يظهر في الانفعالات، عدم الوعي بأثر السلوك، وغياب الإصغاء الحقيقي. هذه سلوكيات قابلة للتعلم والتحسين.","id":199},{"task":"Task 14: Emotional Intelligence","q":"في تعاملك مع أصحاب المصلحة الرئيسيين، كيف تكيّف نهجك بناءً على شخصياتهم؟","opts":["نهج واحد للجميع","تحليل أنماط الشخصية، تكييف أسلوب التواصل ووتيرة المعلومات، وضبط نهج الإقناع لما يلائم كل واحد","تجاهل الفروقات الفردية","التركيز فقط على الأقوى منهم"],"ans":"B","exp":"تكييف النهج مع شخصيات أصحاب المصلحة من سمات القائد الفعال. الفهم العميق للأنماط (تحليلي، تعاوني، صريح، إلخ) يحسن النتائج.","id":200}];